import { G, T, A, O, P } from './domains.js';

export const part2 = [
  {id:127,domain:A,question:"What is network segmentation?",options:["Encrypting all network traffic","Dividing a network into smaller isolated segments to limit lateral movement","Combining multiple networks into one","Installing firewalls at every endpoint"],answer:1,explanation:"Segmentation divides a network into zones (e.g., VLANs) so a breach in one segment cannot easily spread to others.",optionExplanations:["Encrypting network traffic is a separate control from segmentation.","Segmentation isolates network zones so attackers who compromise one segment cannot freely move to others.","Combining networks is consolidation; segmentation is the opposite.","Firewalls at every endpoint describe host-based firewalls, not network segmentation."]},
  {id:128,domain:A,question:"What is a VLAN?",options:["A physical network switch","A virtual network that groups devices logically regardless of physical location","A type of VPN protocol","A wireless network standard"],answer:1,explanation:"A VLAN (Virtual Local Area Network) groups devices logically, enabling segmentation without physical rewiring.",optionExplanations:["A physical network switch is hardware; VLANs are logical configurations on that hardware.","A VLAN groups devices into a logical network segment, independent of physical switch port location.","VPN protocols (IPsec, SSL) create encrypted tunnels; VLANs are logical LAN partitions.","Wireless standards (802.11a/b/g/n/ac/ax) define radio frequencies and speeds, not logical LAN groupings."]},
  {id:129,domain:A,question:"What is the function of an intrusion prevention system (IPS)?",options:["Passively observe network traffic and generate alert notifications for analysts without taking any blocking action","Actively block or drop malicious traffic in real time","Aggregate and retain event logs from network devices for long-term forensic investigation and compliance reporting","Create encrypted IPsec tunnels between geographically separated sites to protect data traversing public networks"],answer:1,explanation:"Unlike an IDS (which only alerts), an IPS actively drops or blocks malicious traffic in line.",optionExplanations:["Passively observing traffic and generating alerts without taking blocking action describes an IDS, not an IPS.","An IPS is inline with the traffic flow and can block, drop, or rate-limit malicious traffic in real time.","Aggregating and retaining logs for forensic investigation describes a SIEM or log management platform.","Creating encrypted IPsec tunnels between sites describes a VPN solution; an IPS inspects plaintext traffic after decryption."]},
  {id:130,domain:A,question:"Which cloud service model provides virtualized infrastructure (servers, storage, networking) as a service?",options:["Software as a Service (SaaS)","Platform as a Service (PaaS)","Infrastructure as a Service (IaaS)","Function as a Service (FaaS)"],answer:2,explanation:"IaaS provides raw compute, storage, and networking; the customer manages OS, apps, and data.",optionExplanations:["SaaS delivers complete software applications to users over the internet (e.g., Microsoft 365, Salesforce).","PaaS provides a platform (OS, middleware, runtime) for developers to build and deploy apps.","IaaS provides virtualized infrastructure components — the customer controls everything from the OS up.","FaaS (serverless) executes individual functions; it is a subset of PaaS."]},
  {id:131,domain:A,question:"What is the shared responsibility model in cloud computing?",options:["The cloud provider is responsible for everything","Security responsibilities are divided between the cloud provider and the customer","The customer bears all security responsibility","Only applies to government cloud deployments"],answer:1,explanation:"In shared responsibility, the provider secures the cloud infrastructure; the customer secures what they put in the cloud.",optionExplanations:["The cloud provider is responsible for physical security, hypervisor, and underlying infrastructure — not everything.","Shared responsibility divides security duties: the provider handles infrastructure; the customer handles data, identity, and apps.","The customer is responsible for what they configure and deploy, but the provider owns physical and virtualization security.","The shared responsibility model applies to all cloud deployments regardless of sector."]},
  {id:132,domain:A,question:"What is a CASB (Cloud Access Security Broker)?",options:["A hardware-based perimeter security appliance that filters all inbound and outbound traffic at the boundary of cloud deployments","Software that sits between users and cloud services to enforce security policies","A type of VPN for cloud access","A subscription-based antivirus product deployed as a cloud-hosted virtual machine agent to scan workloads for malware infections"],answer:1,explanation:"A CASB enforces policies (DLP, authentication, encryption) between cloud users and cloud services.",optionExplanations:["A hardware appliance guards a network boundary but does not sit between users and cloud services enforcing per-app policies the way a CASB does.","A CASB acts as a gatekeeper between users and cloud apps, enforcing policies like DLP, MFA, and encryption.","VPNs create encrypted tunnels; a CASB inspects and controls cloud application traffic.","A cloud antivirus scans for malware but does not broker access between users and SaaS services or enforce cloud-specific security policies."]},
  {id:133,domain:A,question:"What is a software-defined perimeter (SDP)?",options:["A physical firewall at the network edge","A security framework that creates on-demand, per-session encrypted connections hiding infrastructure","A VLAN spanning all network devices","An SDN controller for network routing"],answer:1,explanation:"SDP (zero-trust access) makes infrastructure invisible to unauthorized users and creates encrypted tunnels per session.",optionExplanations:["Physical firewalls define a fixed perimeter; SDP creates dynamic, user-specific perimeters.","SDP hides infrastructure from unauthorized users and creates authenticated, encrypted channels per connection.","VLANs are network segmentation tools; SDP is an access architecture.","SDN controllers manage network topology; SDP controls who can access what in a zero-trust way."]},
  {id:134,domain:A,question:"Which of the following is a key principle of Zero Trust architecture?",options:["Grant implicit trust to all users and devices that originate from within the corporate network perimeter without further verification","Never trust, always verify — verify every user, device, and request regardless of location","Consolidate security architecture by replacing multiple distributed perimeter firewalls with a single centralized security gateway appliance","Permit unrestricted lateral movement between all internal hosts once the network perimeter firewall has been successfully established"],answer:1,explanation:"Zero Trust eliminates implicit trust — every access request must be authenticated and authorized regardless of origin.",optionExplanations:["Trusting internal users by default is the traditional perimeter model that Zero Trust explicitly rejects; every request must be verified regardless of source.","Zero Trust requires continuous verification of identity, device health, and least-privilege access for every request.","Reducing firewalls is an architectural simplification, not a Zero Trust principle; Zero Trust focuses on continuous verification, not perimeter consolidation.","Allowing all LAN traffic is the opposite of Zero Trust; the model requires granular, continuous verification for every request regardless of network location."]},
  {id:135,domain:A,question:"What is a stateful firewall?",options:["A firewall that only filters based on IP addresses","A firewall that tracks the state of network connections and allows return traffic automatically","A next-generation firewall that examines application-layer packet payloads using deep packet inspection to identify and block specific protocols","A packet filter that permits only traffic initiated from the external untrusted network into the trusted internal network"],answer:1,explanation:"A stateful firewall tracks connection state tables and permits return traffic that belongs to established sessions.",optionExplanations:["Filtering only by IP is a packet-filtering firewall, the most basic type.","A stateful firewall tracks connection state (SYN, ESTABLISHED, FIN) to permit legitimate return traffic automatically.","Deep packet inspection at Layer 7 is an NGFW feature, not a defining trait of stateful firewalls, which operate primarily at Layers 3 and 4.","Allowing only inbound traffic would block all outbound communication; stateful firewalls allow return traffic for established sessions initiated from the inside."]},
  {id:136,domain:A,question:"What is the function of a next-generation firewall (NGFW)?",options:["Only filter traffic by port and protocol","Inspect traffic at the application layer, identify users, and enforce application-level policies","Terminate encrypted remote access VPN tunnels for employees connecting from outside the corporate network to reach internal resources","Translate private internal IP addresses to a shared public IP address to allow internal hosts to reach the internet"],answer:1,explanation:"NGFWs combine stateful inspection with DPI, application awareness, user identity, and IPS capabilities.",optionExplanations:["Port and protocol filtering only is a traditional packet-filtering or stateful firewall capability.","NGFWs add deep packet inspection, application identification, user awareness, and integrated IPS beyond stateful inspection.","Terminating VPN tunnels is a VPN concentrator function; NGFWs can integrate VPN but their primary role is application-layer inspection and policy enforcement.","NAT is a standard router and firewall function but not the defining capability of an NGFW; NGFWs add application identification and user-based policy enforcement."]},
  {id:137,domain:A,question:"What is containerization in the context of application security?",options:["Encrypting individual files","Packaging an application and its dependencies into an isolated runtime environment","A method for segmenting network traffic","Virtualizing entire server hardware"],answer:1,explanation:"Containers (e.g., Docker) package apps with their dependencies into isolated environments sharing the host OS kernel.",optionExplanations:["File encryption is a data security control, not containerization.","Containerization isolates applications with their dependencies, improving portability and limiting the impact of compromise.","Network traffic segmentation uses VLANs and firewalls, not containers.","Virtualizing entire server hardware describes full virtual machines (hypervisor-based), not containers."]},
  {id:138,domain:A,question:"What is the primary security concern with serverless computing?",options:["Servers are not patched automatically","Insecure function code and misconfigurations can expose sensitive data","The cloud provider can read all data","Serverless functions cannot be encrypted"],answer:1,explanation:"Serverless shifts OS/infra patching to the provider but the customer is responsible for secure function code and IAM.",optionExplanations:["OS patching in serverless is handled by the provider; the customer is not responsible for that.","The main risk is insecure function code (injection vulnerabilities) and overly permissive IAM roles.","Reputable cloud providers have strong contractual and technical controls against accessing customer data.","Serverless data and code can be encrypted; encryption is supported and recommended."]},
  {id:139,domain:A,question:"Which of the following BEST describes microsegmentation?",options:["Dividing the network into a few large zones","Applying granular security policies to individual workloads or even specific flows","Encrypting micro-transactions","Installing firewalls at every router"],answer:1,explanation:"Microsegmentation creates fine-grained security zones down to individual workloads using software-defined policies.",optionExplanations:["A few large zones is traditional network segmentation, not microsegmentation.","Microsegmentation uses software-defined policies to isolate individual workloads, limiting lateral movement even within data centers.","Micro-transactions are a financial concept unrelated to network security.","Firewalls at routers provide perimeter control; microsegmentation applies inside the perimeter at the workload level."]},
  {id:140,domain:A,question:"What is infrastructure as code (IaC) and its main security implication?",options:["Documenting infrastructure designs using architecture diagrams and flowcharts to train administrators and developers on network topology concepts","Defining infrastructure via code files, meaning misconfigurations can be versioned and replicated at scale","Applying TLS and SSH encryption to all administrative management protocols to protect control-plane communications from eavesdropping","Using robotic assembly systems and automated cable management tools to physically construct and rack servers in data center facilities"],answer:1,explanation:"IaC provisions infrastructure via code (Terraform, CloudFormation); misconfigured templates can spread security flaws at scale.",optionExplanations:["Creating training diagrams is documentation, not IaC; infrastructure as code means machine-readable definition files that provision real infrastructure automatically.","IaC automates infrastructure provisioning through code, meaning one misconfigured template can replicate vulnerabilities everywhere.","Encrypting management protocols is a security hardening practice, not IaC; IaC defines the infrastructure itself through code files, not just its communications.","Physical data center automation is distinct from IaC; infrastructure as code provisions logical and virtual resources through software, not hardware assembly."]},
  {id:141,domain:A,question:"What security principle does a honeynet implement?",options:["Preventing attackers from entering the network","Luring attackers into a decoy network environment to monitor their techniques","Encrypting sensitive network segments","Providing redundant network paths"],answer:1,explanation:"A honeynet is multiple honeypots forming a fake network, used to study attacker behavior in a realistic environment.",optionExplanations:["Preventing attackers is the goal of perimeter security; a honeynet lets attackers in deliberately.","A honeynet creates a realistic decoy environment to observe attacker TTPs without risk to real systems.","Encrypting segments is VPN or VLAN security; a honeynet is a deception technology.","Redundant paths describe high availability architecture, not deception technology."]},
  {id:142,domain:A,question:"What is a site-to-site VPN?",options:["A VPN used by individual remote employees","A permanent encrypted tunnel connecting two entire networks (e.g., two office locations)","A VPN that only encrypts web traffic","A VPN that uses HTTPS for encryption"],answer:1,explanation:"A site-to-site VPN creates a persistent encrypted tunnel between two networks, typically using IPsec.",optionExplanations:["Individual remote user access is a remote access VPN (client-to-site), not site-to-site.","A site-to-site VPN permanently links two network locations so all traffic between them is encrypted.","Encrypting only web traffic describes SSL/TLS proxying, not a site-to-site VPN.","While TLS VPNs exist, site-to-site VPNs traditionally use IPsec IKEv2."]},
  {id:143,domain:A,question:"Which of the following is a benefit of using HTTPS over HTTP?",options:["Faster page loading speeds","Encryption and authentication of web traffic","Reduced server resource usage","Improved database query performance"],answer:1,explanation:"HTTPS uses TLS to encrypt traffic between client and server and authenticates the server via a certificate.",optionExplanations:["HTTPS adds TLS overhead; it is not faster than HTTP.","HTTPS provides encryption of traffic in transit and server identity authentication via digital certificates.","TLS processing adds CPU overhead, not reduced resource usage.","HTTPS secures the transport layer; it has no impact on database performance."]},
  {id:144,domain:A,question:"What is the purpose of network address translation (NAT)?",options:["Apply IPsec tunnel mode encryption to all traffic passing between internal corporate hosts and external internet-facing destination addresses","Map private IP addresses to one or more public IP addresses to allow internet access","Divide a flat corporate network into logically isolated broadcast domains using IEEE 802.1Q VLAN tagging and inter-VLAN routing","Require valid credentials and 802.1X certificate-based authentication before any host is permitted to obtain a network lease and connect"],answer:1,explanation:"NAT allows multiple devices with private IPs to share public IP addresses, providing connectivity and hiding internal addresses.",optionExplanations:["IPsec encrypts traffic in transit but does not translate addresses; NAT specifically remaps private IP addresses to public ones to enable internet routing.","NAT translates private internal IP addresses to a public IP address for internet communication.","VLANs segment network traffic into broadcast domains but do not translate addresses; NAT maps private addresses to public ones for internet access.","802.1X enforces access control at the port level before devices join the network; NAT remaps addresses after devices are already connected and communicating."]},
  {id:145,domain:A,question:"A company implements a WAF (Web Application Firewall). What does it primarily protect against?",options:["Network-layer DDoS attacks","Application-layer attacks such as SQL injection, XSS, and CSRF","Physical intrusion into the data center","Malware on employee endpoints"],answer:1,explanation:"A WAF inspects HTTP/S traffic and blocks web application attacks like SQLi, XSS, and CSRF.",optionExplanations:["Network-layer DDoS is mitigated by DDoS scrubbing services and network-layer firewalls, not WAFs.","WAFs analyze HTTP requests and responses to detect and block OWASP Top 10 attacks like SQLi and XSS.","Physical intrusion is addressed by physical security controls, not a WAF.","Endpoint malware is addressed by EDR and antivirus, not a WAF."]},
  {id:146,domain:A,question:"Which wireless attack creates an access point with the same SSID as a legitimate network to intercept traffic?",options:["Deauthentication attack","Evil twin attack","Bluejacking","War driving"],answer:1,explanation:"An evil twin AP broadcasts the same SSID as the legitimate network, tricking users into connecting to the attacker's AP.",optionExplanations:["A deauthentication attack disconnects clients from a legitimate AP; an evil twin then offers an alternative connection.","An evil twin creates a rogue AP with the same SSID to perform a MITM attack on wireless clients.","Bluejacking sends unsolicited Bluetooth messages; it is not a Wi-Fi attack.","War driving scans for open or weak Wi-Fi networks while driving; it doesn't create rogue APs."]},
  {id:147,domain:A,question:"What is the difference between IDS and IPS?",options:["IDS blocks traffic; IPS only monitors","IDS monitors and alerts; IPS monitors and actively blocks malicious traffic","They are identical","IPS is only for wireless networks"],answer:1,explanation:"An IDS detects and alerts on threats; an IPS sits inline and takes active blocking action.",optionExplanations:["It is IPS that blocks; IDS only monitors and alerts.","IDS (Intrusion Detection System) generates alerts; IPS (Intrusion Prevention System) actively blocks threats inline.","IDS and IPS serve different purposes: detection versus prevention.","Both IDS and IPS can be deployed on wired or wireless networks."]},
  {id:148,domain:A,question:"Which of the following BEST describes an air gap?",options:["A gap between firewall rules","Physical isolation of a system from all external networks","A network that uses wireless only","A type of VPN tunnel"],answer:1,explanation:"An air gap physically isolates a system so it has no network connection to external or untrusted networks.",optionExplanations:["Firewall rule gaps are misconfigurations, not intentional isolation.","An air-gapped system is completely disconnected from external networks, providing maximum isolation for sensitive systems.","Wireless-only networks are still connected networks, not air-gapped.","VPN tunnels connect networks through encryption; they do not isolate systems from networks."]},
  {id:149,domain:A,question:"What is a load balancer's role in availability and security?",options:["Encrypt traffic between servers","Distribute traffic across multiple servers and can filter malicious requests","Replace firewalls in the network","Authenticate users before they reach servers"],answer:1,explanation:"Load balancers improve availability by distributing traffic and can perform SSL offloading and basic filtering.",optionExplanations:["Load balancers can offload SSL (terminate encryption), not create it between backend servers.","Load balancers distribute incoming requests across server pools, improving availability and sometimes filtering malicious traffic.","Load balancers complement firewalls but do not replace them.","Authentication is handled by IAM systems and identity providers, not load balancers."]},
  {id:150,domain:A,question:"What is the primary purpose of network access control (NAC)?",options:["Encrypt wireless traffic","Ensure devices meet security policies before connecting to the network","Provide physical access to secure rooms","Block all external traffic"],answer:1,explanation:"NAC checks device health (OS version, patches, AV status) before granting network access.",optionExplanations:["Wireless encryption is handled by WPA2/WPA3; NAC is about access control decisions.","NAC enforces posture assessment — verifying patch level, antivirus currency, and configuration before allowing network access.","Physical access control is handled by badge readers and security guards.","Blocking all external traffic is a firewall rule; NAC controls which devices can connect internally."]},
  {id:151,domain:A,question:"Which protocol is used to securely transfer files between systems?",options:["FTP","TFTP","SFTP","HTTP"],answer:2,explanation:"SFTP (SSH File Transfer Protocol) runs over SSH and provides encrypted file transfer.",optionExplanations:["FTP transfers files in plaintext; credentials and data are unprotected.","TFTP is a minimal UDP-based protocol with no authentication or encryption.","SFTP encrypts the entire session including credentials and file data using SSH.","HTTP transfers web content, not files, and is unencrypted by default."]},
  {id:152,domain:A,question:"What is port security on a network switch?",options:["Encrypting all switch ports","Restricting which MAC addresses can connect to a switch port","Blocking all unused ports with a firewall","Enabling VLANs on all ports"],answer:1,explanation:"Port security limits the MAC addresses allowed on each switch port, preventing unauthorized devices from connecting.",optionExplanations:["Switch ports do not encrypt traffic; encryption occurs at higher layers.","Port security limits the specific MAC addresses permitted on a physical switch port.","Blocking unused ports via firewall rules describes perimeter security; port security operates on the switch itself.","Enabling VLANs is a segmentation configuration; port security is about controlling which devices connect."]},
  {id:153,domain:A,question:"What is the purpose of DNSSEC?",options:["Encrypt DNS queries in transit","Add digital signatures to DNS records to prevent DNS spoofing","Replace DNS with a more secure protocol","Provide private DNS resolution for internal networks"],answer:1,explanation:"DNSSEC signs DNS records so resolvers can verify records haven't been tampered with, preventing cache poisoning.",optionExplanations:["DNS-over-HTTPS (DoH) or DNS-over-TLS (DoT) encrypts DNS queries; DNSSEC authenticates the records themselves.","DNSSEC uses digital signatures on DNS records to ensure authenticity and integrity, preventing cache poisoning.","DNSSEC extends existing DNS with signatures; it does not replace the protocol.","Split-horizon DNS or internal resolvers provide private DNS; DNSSEC is about authentication, not privacy."]},
  {id:154,domain:A,question:"What is the role of a proxy server in network security?",options:["Establish encrypted VPN tunnels between remote employee devices and the corporate network using client-side tunneling software and certificates","Intercept and inspect traffic on behalf of clients, hiding their identity and filtering content","Distribute dynamic IP addresses and network configuration parameters to hosts automatically using a lease-based DHCP address management system","Offload TLS decryption processing from backend application servers by terminating encrypted connections at a dedicated load balancer tier"],answer:1,explanation:"A forward proxy forwards client requests, masks client IPs, and can filter or cache web content.",optionExplanations:["VPN concentrators establish encrypted tunnels for remote access; a proxy inspects and forwards client requests to destinations, not tunnel remote users.","A proxy intercepts client requests, provides anonymity, and can filter URLs, block malware, and cache content.","DHCP assigns IP addresses to devices; a proxy server intercepts and inspects client traffic and filters content, not assigns network addresses.","TLS termination at a load balancer is SSL offloading; a forward proxy intercepts client requests to inspect and filter content, not terminate server-side TLS."]},
  {id:155,domain:A,question:"What is a reverse proxy?",options:["A client-side forward proxy that conceals user IP addresses by routing all outbound web requests through an intermediary server","A server that sits in front of backend servers and forwards external requests to them","A dedicated TLS-terminating proxy that only accepts HTTPS connections and actively rejects all unencrypted HTTP client requests","A VPN concentrator that terminates incoming encrypted tunnels and routes authenticated users to their permitted internal network segments"],answer:1,explanation:"A reverse proxy accepts external connections and forwards them to internal servers, hiding backend topology.",optionExplanations:["A forward proxy hides client identities by proxying outbound requests; a reverse proxy serves incoming external requests on behalf of backend servers, not clients.","A reverse proxy sits in front of backend servers, providing load balancing, caching, and SSL termination.","Terminating only HTTPS is a filtering behavior; a reverse proxy is defined by its position in front of backend servers and forwarding external requests to them.","VPN concentrators handle remote access tunnels; a reverse proxy sits in front of web servers and forwards external HTTP/S requests to backend services."]},
  {id:156,domain:A,question:"Which of the following BEST describes a UTM (Unified Threat Management) appliance?",options:["A device that only provides firewalling","A single device combining firewall, IPS, antivirus, content filtering, and VPN","A dedicated intrusion prevention system","A hardware load balancer"],answer:1,explanation:"A UTM consolidates multiple security functions (firewall, IPS, AV, content filtering, VPN) into a single appliance.",optionExplanations:["Firewalling only describes a traditional firewall; UTM provides many more capabilities.","UTM consolidates firewall, IPS, antivirus, content/URL filtering, and VPN into one device, simplifying management.","A standalone IPS only detects/prevents intrusions; UTM includes IPS plus much more.","A hardware load balancer distributes traffic; UTM is a security-focused multi-function device."]},
  {id:157,domain:A,question:"What is east-west traffic in a data center context?",options:["Traffic entering and leaving the data center (north-south)","Traffic moving laterally between servers within the data center","Traffic on the external internet","Traffic between the data center and cloud providers"],answer:1,explanation:"East-west traffic moves between servers inside the data center; north-south traffic moves in/out of the data center.",optionExplanations:["North-south traffic enters and leaves the data center from external clients or the internet.","East-west traffic flows laterally between servers, VMs, and microservices within the data center — a key target for lateral movement.","External internet traffic is north-south from the data center's perspective.","Traffic between data centers and cloud providers is also considered north-south."]},
  {id:158,domain:A,question:"What is the purpose of endpoint detection and response (EDR)?",options:["Encrypt data at rest on endpoints","Monitor endpoint activity for threats and provide investigation and response capabilities","Replace antivirus entirely","Provide VPN access for remote users"],answer:1,explanation:"EDR collects telemetry from endpoints, detects advanced threats, and provides tools for investigation and automated response.",optionExplanations:["Full-disk encryption (FDE) encrypts data at rest; EDR is a detection and response tool.","EDR continuously monitors endpoint behavior, detects anomalies, and enables rapid investigation and containment.","EDR complements traditional antivirus rather than replacing it; both serve different roles.","Remote access VPNs are provided by VPN solutions, not EDR."]},
  {id:159,domain:A,question:"What is the function of a SIEM (Security Information and Event Management) system?",options:["Actively block network intrusion attempts in real time by dropping malicious packets based on inline IPS rule signatures","Collect, correlate, and analyze log data from multiple sources to detect security events","Apply mutual TLS authentication and encryption to API communication channels between distributed security tool components and agents","Provision and deprovision user accounts, group memberships, and role-based permissions across enterprise identity management systems"],answer:1,explanation:"SIEM aggregates logs from network, endpoints, and apps, correlating events to identify threats and generate alerts.",optionExplanations:["Real-time packet blocking is the function of an IPS; a SIEM collects and correlates log data to detect events but does not block traffic inline.","SIEM collects and correlates log data from diverse sources to detect patterns indicating security incidents.","Encrypting tool communications is a security hardening measure; a SIEM's core function is aggregating and correlating log data from diverse sources to surface threats.","User provisioning is an IAM function; a SIEM focuses on collecting, correlating, and analyzing security event data, not managing user accounts or access rights."]},
  {id:160,domain:A,question:"What is meant by 'secure by design'?",options:["Security controls added after development is complete","Building security into systems from the beginning of the design process","Designing systems only to be physically secure","Requiring security certifications for all software"],answer:1,explanation:"Secure by design integrates security requirements into the earliest phases of architecture and development.",optionExplanations:["Adding security after development is 'bolting on' security, which is less effective and more costly.","Secure by design means security is a fundamental requirement considered from initial architecture through deployment.","Physical security is one aspect; secure by design applies to all security dimensions including software.","Certifications may be required but secure by design is about the process, not the certification."]},
  {id:161,domain:A,question:"What is the purpose of patch management?",options:["Capture and analyze packet flows on network segments to identify unusual bandwidth consumption or anomalous protocol behavior patterns","Apply updates to fix vulnerabilities and improve security in systems and software","Create scheduled offline copies of critical server data to enable restoration of services after hardware failure or ransomware events","Review and adjust role-based access control assignments to enforce separation of duties across enterprise applications and systems"],answer:1,explanation:"Patch management keeps systems updated to close known vulnerabilities before they can be exploited.",optionExplanations:["Network traffic analysis detects anomalies but does not update software; patch management specifically applies fixes and updates to address known vulnerabilities.","Patch management systematically identifies, tests, and deploys software updates to remediate known vulnerabilities.","Backup creates data copies for recovery; patch management applies security updates to fix vulnerabilities in operating systems and applications, not back up data.","Managing access privileges is an IAM function; patch management focuses on deploying software updates and security fixes, not controlling user permissions."]},
  {id:162,domain:A,question:"Which of the following BEST describes an application whitelist?",options:["A catalog of prohibited software titles that are explicitly denied execution on all managed enterprise endpoint devices","A list of approved applications that are permitted to run on a system","A firewall access control entry that explicitly permits inbound and outbound HTTP and HTTPS traffic through the perimeter firewall","A network access control list specifying which IP addresses are permitted to establish connections with protected internal resources"],answer:1,explanation:"Application whitelisting allows only pre-approved executables to run, blocking all others by default.",optionExplanations:["A catalog of blocked applications describes a blacklist or denylist; an allowlist specifically permits only listed approved applications and blocks everything else.","Application whitelisting (now often called allowlisting) permits only explicitly approved applications to execute.","A firewall rule controls network traffic flows; an application whitelist controls which software executables are permitted to run on endpoint systems.","An IP allowlist restricts network-level connectivity by address; an application whitelist controls which programs are permitted to execute on local systems."]},
  {id:163,domain:A,question:"What is the purpose of a sandbox in security?",options:["Store recovered malware samples","Execute untrusted code in an isolated environment to observe its behavior","Block malware at the email gateway","Encrypt sensitive files before storage"],answer:1,explanation:"A sandbox isolates suspicious code so it can run and be analyzed without risking the production environment.",optionExplanations:["Malware samples are stored in secure repositories; a sandbox is used for dynamic analysis.","A sandbox executes suspicious files in isolation to observe behavior without contaminating real systems.","Email gateways filter malicious attachments; sandboxing goes further by executing them for analysis.","File encryption is a data protection control, not sandboxing."]},
  {id:164,domain:A,question:"What is a software bill of materials (SBOM)?",options:["A procurement document listing the licensing fees, renewal terms, and usage rights for each commercial software product acquired","A comprehensive list of all components and dependencies in a software product","An automated scan output listing security weaknesses discovered in a system, ranked and prioritized by CVSS severity scores","A version history document recording each code modification, author, and rationale made throughout the software development lifecycle"],answer:1,explanation:"An SBOM lists all open-source and third-party components in a product, enabling vulnerability tracking.",optionExplanations:["A software invoice covers licensing and procurement costs; an SBOM inventories the actual technical components and open-source dependencies in a software product.","An SBOM inventories all software components including open-source libraries, enabling rapid response when a component has a CVE.","A vulnerability scan report identifies security flaws; an SBOM catalogs all software components and dependencies, enabling future vulnerability tracking rather than listing current ones.","A change log tracks code modifications over time; an SBOM inventories all third-party components and dependencies present in the final software product."]},
  {id:165,domain:O,question:"What are the six phases of the incident response lifecycle (NIST)?",options:["Identify, Protect, Detect, Respond, Recover, Learn","Preparation, Detection, Analysis, Containment, Eradication, Recovery","Plan, Do, Check, Act, Review, Improve","Triage, Escalation, Investigation, Remediation, Reporting, Closure"],answer:1,explanation:"NIST SP 800-61 defines: Preparation, Detection & Analysis, Containment/Eradication/Recovery, and Post-Incident Activity.",optionExplanations:["The NIST Cybersecurity Framework uses Identify, Protect, Detect, Respond, Recover — a different framework.","NIST SP 800-61 incident response lifecycle: Preparation, Detection & Analysis, Containment/Eradication/Recovery, Post-Incident Activity.","Plan-Do-Check-Act is the ISO 27001 PDCA cycle, not the incident response lifecycle.","Triage, escalation, etc. describe helpdesk workflows, not the formal NIST incident response lifecycle."]},
  {id:166,domain:O,question:"What is the purpose of containment during incident response?",options:["Identify the root cause of the incident","Prevent the incident from spreading to additional systems","Rebuild affected systems from backup","Document findings for legal proceedings"],answer:1,explanation:"Containment isolates affected systems to stop the spread of an attack while preserving evidence.",optionExplanations:["Root cause analysis occurs during the detection and analysis phase, before or alongside containment.","Containment limits the damage by isolating infected systems to prevent lateral spread while investigation continues.","Rebuilding systems is part of the recovery phase, after eradication.","Documenting for legal purposes is post-incident activity and chain of custody, not containment."]},
  {id:167,domain:O,question:"What is a chain of custody in digital forensics?",options:["The sequence of events during an attack","The documented record of who handled evidence and when","A list of compromised systems","A forensic analysis report"],answer:1,explanation:"Chain of custody documents every person who handled evidence, ensuring its integrity for legal proceedings.",optionExplanations:["The sequence of attack events is a timeline or attack narrative, not chain of custody.","Chain of custody is the chronological documentation of evidence handling from collection through legal proceedings.","Compromised system lists are part of incident tracking, not chain of custody.","A forensic analysis report summarizes findings; chain of custody is the handling record."]},
  {id:168,domain:O,question:"What is the difference between eradication and recovery in incident response?",options:["They are the same phase","Eradication removes the threat; recovery restores systems to normal operation","Recovery removes the threat; eradication restores systems","Eradication only applies to malware; recovery applies to hardware"],answer:1,explanation:"Eradication removes all traces of the threat (malware, backdoors); recovery restores services and verifies normal operation.",optionExplanations:["They are distinct phases in the incident response lifecycle.","Eradication removes the root cause and threat artifacts; recovery brings affected systems back online safely.","Recovery does not remove the threat; eradication does. Order matters: eradicate first, then recover.","Both phases apply to all incident types including malware, unauthorized access, and hardware failures."]},
  {id:169,domain:O,question:"What is vulnerability scanning?",options:["Actively exploiting vulnerabilities to prove they exist","Automated identification of vulnerabilities in systems, applications, or networks","Reviewing source code for security flaws","Interviewing staff about security practices"],answer:1,explanation:"Vulnerability scanning uses automated tools to identify known vulnerabilities without exploiting them.",optionExplanations:["Actively exploiting vulnerabilities is penetration testing, not vulnerability scanning.","Vulnerability scanners (Nessus, OpenVAS, Qualys) probe systems for known CVEs, misconfigurations, and missing patches.","Source code review is static analysis; vulnerability scanning tests live systems.","Staff interviews are part of a security assessment or audit, not vulnerability scanning."]},
  {id:170,domain:O,question:"What is the difference between a vulnerability scan and a penetration test?",options:["Both processes use automated scanning tools to identify and actively exploit weaknesses in target systems and report findings","A vulnerability scan identifies weaknesses; a penetration test actively exploits them to assess impact","A penetration test is automated; a vulnerability scan is manual","Vulnerability scans are illegal without permission; penetration tests are not"],answer:1,explanation:"Vuln scanning finds known vulnerabilities; pen testing attempts to exploit them to demonstrate real-world impact.",optionExplanations:["This conflates both activities; a vulnerability scan only identifies weaknesses passively, while a penetration test actively exploits them to demonstrate real-world impact.","Vulnerability scanning identifies potential weaknesses; penetration testing actively exploits them to determine actual risk.","Vulnerability scans are automated; penetration tests combine automated tools with skilled manual techniques.","Both require written authorization; neither is legal without explicit permission from the system owner."]},
  {id:171,domain:O,question:"What is the purpose of a SOAR platform?",options:["Provide real-time threat intelligence","Automate incident response workflows to reduce manual effort and response time","Replace SIEM systems","Store forensic evidence"],answer:1,explanation:"SOAR (Security Orchestration, Automation and Response) automates repetitive tasks and orchestrates response playbooks.",optionExplanations:["Threat intelligence is provided by threat intelligence platforms and feeds; SOAR consumes that intelligence.","SOAR automates alert triage, enrichment, and response actions, reducing mean time to respond (MTTR).","SOAR complements SIEM (which detects); SOAR acts on those detections.","Evidence storage is handled by forensic repositories and chain of custody systems."]},
  {id:172,domain:O,question:"What is threat hunting?",options:["Running scheduled, signature-based antivirus scans across all endpoints to automatically detect and quarantine known malware infections","Proactively searching for hidden threats in an environment not yet detected by automated tools","Executing predefined containment and remediation steps in response to a security alert that has already been generated by tools","Installing decoy systems and fake credentials on the network to lure and record attacker reconnaissance and lateral movement activity"],answer:1,explanation:"Threat hunting is a proactive, hypothesis-driven search for adversaries that have evaded automated detection.",optionExplanations:["Automated signature scanning is reactive malware detection; threat hunting is a proactive, human-led search for stealthy threats that evade automated security tools.","Threat hunting proactively searches for adversaries already inside a network that haven't triggered automated alerts.","Executing predefined response steps describes incident response, not threat hunting; threat hunting proactively searches for threats before any automated alert has fired.","Installing deception technologies like honeypots is a passive detection technique; threat hunting is an active analyst-driven search for hidden adversary activity."]},
  {id:173,domain:O,question:"Which of the following BEST describes a data loss prevention (DLP) solution?",options:["Apply AES-256 encryption to all files stored on servers and endpoint devices to protect data confidentiality at rest","Monitor and control data transfers to prevent unauthorized exfiltration of sensitive data","Back up data to prevent accidental loss","Monitor network traffic for signatures matching known attack patterns and generate alerts for analysts investigating potential compromises"],answer:1,explanation:"DLP monitors data in use, in motion, and at rest to prevent unauthorized transfer of sensitive information.",optionExplanations:["Encrypting data at rest protects stored data from physical access; DLP monitors and controls active data transfers to prevent exfiltration, not encrypt stored data.","DLP identifies sensitive data (PII, financial, IP) and enforces policies preventing unauthorized exfiltration.","Backups address accidental loss; DLP addresses intentional or negligent data exfiltration.","Detecting attack signatures in traffic describes IDS/IPS; DLP specifically monitors data content and movement to prevent sensitive information from leaving authorized boundaries."]},
  {id:174,domain:O,question:"What is the purpose of log management in security operations?",options:["Apply symmetric encryption to all log entries before writing them to archival storage to protect their confidentiality and integrity","Collect, store, and analyze logs to support incident detection, investigation, and compliance","Serve as a full functional substitute for the correlation, alerting, and reporting capabilities provided by enterprise SIEM platforms","Trigger automated firewall blocks and account lockouts immediately whenever a security monitoring tool generates a detection alert"],answer:1,explanation:"Log management centralizes logs from all sources, enabling correlation, retention for compliance, and forensic investigation.",optionExplanations:["Encrypting log files is a security hardening measure; log management encompasses collection, storage, retention, and analysis of logs to support security and compliance.","Log management collects, normalizes, stores, and makes logs searchable for security analysis and compliance.","Log management handles collection and storage but does not replace SIEM; a SIEM adds correlation rules, real-time alerting, and threat detection on top of logs.","Automated response to alerts describes SOAR or active defense; log management stores and organizes log data to support analysis and investigation by analysts."]},
  {id:175,domain:O,question:"What is privileged access management (PAM)?",options:["Granting all users administrator rights","Controlling and monitoring access for accounts with elevated permissions","Providing VPN access to executives only","Managing physical access to server rooms"],answer:1,explanation:"PAM enforces least privilege for admin/service accounts, requiring justification and session recording for privileged access.",optionExplanations:["Granting all users admin rights is the opposite of PAM and violates least privilege.","PAM controls who can use privileged accounts, when, for what purpose, and records all sessions for audit.","VPN access is managed by network access controls, not PAM.","Physical server room access is managed by physical security, not PAM."]},
  {id:176,domain:O,question:"What is multi-factor authentication (MFA) and why is it important?",options:["Configuring a single account with two separate static passwords that must both be entered sequentially during each login attempt","Requiring verification from two or more different factor categories, making account takeover much harder","A self-service portal that allows users to recover account access by verifying ownership through a registered backup email address","Distributing a shared username and password combination among multiple team members to access a single shared service account"],answer:1,explanation:"MFA combines something you know, have, or are — compromising one factor alone cannot grant access.",optionExplanations:["Using two passwords is still just a knowledge factor used twice; MFA requires factors from different categories such as something you know plus something you have.","MFA requires factors from different categories (knowledge, possession, inherence), making credential theft insufficient alone.","Self-service password reset is an account recovery mechanism; MFA is an authentication control requiring multiple different factor types before granting initial access.","Sharing credentials among users is a security violation that undermines accountability; MFA adds independent verification factors for each user's individual authentication."]},
  {id:177,domain:O,question:"What is a playbook in the context of incident response?",options:["A manual listing all software installed on servers","A documented, step-by-step procedure for responding to a specific type of security incident","A structured training curriculum covering security fundamentals, tool operations, and certification exam preparation for new security analysts","A curated feed of IP addresses, domain names, and file hashes associated with known malicious threat actor infrastructure"],answer:1,explanation:"An IR playbook provides predefined, tested procedures (steps, decisions, owners) for handling specific incident types.",optionExplanations:["Software inventory lists are configuration management items, not IR playbooks.","A playbook is a documented workflow guiding responders through each step for a specific incident scenario.","A training curriculum educates staff over time; a playbook is an operational procedure that guides analysts through the specific steps of an active incident response.","A list of threat indicators describes a threat intelligence feed or IOC list; a playbook is a step-by-step procedural guide for responding to a specific incident type."]},
  {id:178,domain:O,question:"What does MTTR stand for and why does it matter?",options:["Maximum Threat Tolerance Ratio — the highest volume of concurrent attack traffic an organization's defenses can absorb before failing","Mean Time To Repair (Respond) — the average time to restore a system after failure or incident","Minimum Time To Recovery — the theoretical shortest duration in which a system could be restored under optimal recovery conditions","Maximum Time To Resolve — the deadline for incident closure"],answer:1,explanation:"MTTR measures average recovery/repair time; lower MTTR means faster incident response and reduced business impact.",optionExplanations:["Maximum Threat Tolerance Ratio is not a real metric; MTTR stands for Mean Time To Repair, measuring the average duration to restore a system after an incident.","MTTR (Mean Time to Repair/Respond/Recover) is a key operational metric measuring average restoration time.","Minimum Time To Recovery is not a standard metric; MTTR is Mean Time To Repair, an average across multiple incidents, not a best-case theoretical minimum.","MTTR measures the average, not a deadline."]},
  {id:179,domain:O,question:"What is a security baseline?",options:["The lowest acceptable security level for any system","A defined set of minimum security configuration requirements for systems","A zero-security default state","The starting point before any patches are applied"],answer:1,explanation:"A security baseline defines the minimum hardening and configuration standards all systems must meet.",optionExplanations:["The lowest acceptable level could imply weak security; a baseline defines minimum required hardening, not the floor.","A security baseline is a documented standard specifying minimum security configurations for OS, apps, and services.","A zero-security state is an unsecured system; a baseline defines required minimum security standards.","A baseline is an ongoing standard, not tied to the pre-patch state."]},
  {id:180,domain:O,question:"What is the purpose of a forensic image?",options:["Generate a deduplicated, compressed archive of selected directories on a backup server for use in disaster recovery restoration","Capture a bit-for-bit copy of storage media for forensic investigation without altering the original","Use antivirus scanning tools to detect, quarantine, and remove malicious files from a compromised storage device before analysis","Apply full-disk encryption to evidence drives before transferring them to an external forensic analysis workstation for examination"],answer:1,explanation:"A forensic image is a bit-exact duplicate of storage media, preserving evidence while protecting the original from modification.",optionExplanations:["A compressed backup selects and compresses files for recovery; a forensic image captures every bit exactly as-is, preserving deleted data and metadata needed for investigation.","Forensic imaging creates an exact replica of storage media including deleted files, slack space, and metadata.","Removing malware from a drive alters evidence and corrupts forensic integrity; a forensic image captures the drive unchanged so evidence is preserved for legal proceedings.","Encrypting an evidence drive before imaging alters its state and would corrupt the forensic process; a forensic image captures the drive in its original unmodified state."]},
  {id:181,domain:O,question:"Which of the following BEST describes identity and access management (IAM)?",options:["Controlling employee and visitor entry through physical doors using keycard readers, PIN pads, and visitor sign-in management systems","The processes and technologies for ensuring the right people access the right resources at the right times","A stateful packet inspection security appliance that enforces access control lists at the boundary between trusted and untrusted network zones","Hashing and salting user passwords before database storage and transmitting credentials only over encrypted channels to prevent exposure"],answer:1,explanation:"IAM encompasses provisioning, authentication, authorization, and deprovisioning of user identities and access rights.",optionExplanations:["Physical access control manages entry to facilities; IAM governs logical access to digital systems, resources, and data across an organization's IT environment.","IAM governs who can access which resources, under what conditions, using authentication and authorization controls.","A firewall controls network traffic at boundaries; IAM manages user identities, authentication, and authorization to ensure appropriate access to digital resources and systems.","Password hashing protects credential storage; IAM encompasses the full lifecycle of identity management including provisioning, authentication, authorization, and access reviews."]},
  {id:182,domain:O,question:"What is a false positive in the context of security monitoring?",options:["An attack that goes undetected","An alert generated for benign activity incorrectly flagged as malicious","A confirmed security incident","A vulnerability that cannot be exploited"],answer:1,explanation:"False positives waste analyst time responding to alerts for benign activity incorrectly classified as threats.",optionExplanations:["An undetected attack is a false negative — a missed detection.","A false positive is a benign event incorrectly identified as malicious, leading to unnecessary investigation.","A confirmed incident is a true positive — a real threat correctly detected.","An unexploitable vulnerability is a theoretical risk; a false positive is a detection accuracy issue."]},
  {id:183,domain:O,question:"What is an SLA in the context of security operations?",options:["A technical encryption standard","A contractual agreement defining service performance expectations, including security response times","A type of network attack","A software license agreement"],answer:1,explanation:"An SLA (Service Level Agreement) defines measurable service expectations such as incident response times.",optionExplanations:["Encryption standards are cryptographic protocols like AES or TLS; an SLA is a contractual document.","An SLA defines performance metrics and commitments between a service provider and customer, including security response times.","SLA is not an attack type.","A software license agreement (EULA) governs software use; SLAs govern service performance."]},
  {id:184,domain:O,question:"What is the goal of a business continuity plan (BCP)?",options:["Respond to security incidents","Ensure critical business functions continue during and after a disruption","Comply with data privacy regulations","Train employees in cybersecurity"],answer:1,explanation:"A BCP identifies critical processes and provides strategies to maintain them during disasters or disruptions.",optionExplanations:["Incident response plans handle security incidents; BCP covers broader operational continuity.","A BCP ensures the organization can continue critical operations during disasters, power outages, or other disruptions.","Privacy regulations are addressed by compliance programs; BCP is about operational continuity.","Security awareness training is an administrative control; BCP is a continuity planning document."]},
  {id:185,domain:O,question:"What is the difference between RTO and RPO?",options:["RTO and RPO are identical business continuity metrics used interchangeably to describe how quickly systems must recover after disasters","RTO is the maximum acceptable downtime; RPO is the maximum acceptable data loss","RPO is the recovery time; RTO is the data loss tolerance","RTO applies to hardware; RPO applies to software"],answer:1,explanation:"RTO (Recovery Time Objective) = max acceptable downtime. RPO (Recovery Point Objective) = max acceptable data loss.",optionExplanations:["They are not the same metric; RTO measures maximum tolerable downtime, while RPO measures maximum tolerable data loss — they address different dimensions of recovery planning.","RTO defines how quickly systems must be restored; RPO defines how old a backup can be before data loss is unacceptable.","RPO does not measure recovery time — that is RTO.","Both metrics apply to all resource types, not just hardware or software specifically."]},
  {id:186,domain:O,question:"What is a tabletop exercise?",options:["A live network emulation environment where engineers actively test firewall rule changes against simulated attack traffic without production impact","A discussion-based exercise where teams walk through incident response scenarios without activating real systems","A complete operational activation of all disaster recovery systems and live failover to backup infrastructure to validate recovery procedures","A physical safety rehearsal where employees practice building evacuation routes and security guards respond to a simulated intruder breach"],answer:1,explanation:"Tabletop exercises involve key stakeholders walking through hypothetical scenarios to identify gaps in plans.",optionExplanations:["A network simulation tests technical configuration; a tabletop exercise is discussion-based, with teams verbally walking through scenarios rather than activating any real systems.","A tabletop exercise is a discussion-based scenario walkthrough that identifies process gaps without triggering real systems.","A full-scale DR test activates real systems and failover; a tabletop exercise is purely discussion-based and identifies plan gaps without activating or stressing any systems.","Physical evacuation drills are building safety exercises; a tabletop exercise focuses on decision-making and coordination for information security incident response scenarios."]},
  {id:187,domain:O,question:"What is full disk encryption (FDE)?",options:["Encrypting only sensitive files on a disk","Encrypting the entire storage drive so data is unreadable without proper authentication","Encrypting data in transit to external drives","Protecting only structured database table files using column-level encryption while leaving the operating system and other files unencrypted"],answer:1,explanation:"FDE (e.g., BitLocker, FileVault) encrypts all data on the disk, protecting against physical theft.",optionExplanations:["Encrypting only specific files is file-level encryption; FDE encrypts the entire disk.","FDE encrypts all data on the drive, making it unreadable if the drive is removed or the device is stolen.","Encrypting data in transit to external drives involves removable media policies and endpoint DLP.","Column-level database encryption protects specific fields; FDE encrypts the entire storage drive, protecting all data including the OS, so the disk is unreadable without authentication."]},
  {id:188,domain:O,question:"What is the purpose of a user behavior analytics (UBA) tool?",options:["Track the volume of data transferred across each network segment to enforce bandwidth allocation policies and detect capacity overuse","Analyze patterns of user activity to detect anomalous behavior indicating insider threats or compromised accounts","Provision, synchronize, and manage user identities, group memberships, and access permissions within Microsoft Active Directory environments","Push security vulnerability patches to endpoint devices automatically using a centralized software update management and distribution server"],answer:1,explanation:"UBA/UEBA establishes behavioral baselines and alerts on deviations like unusual login times or large data downloads.",optionExplanations:["Monitoring bandwidth usage describes network performance management; UBA analyzes user behavior patterns to detect anomalies that may indicate insider threats or account compromise.","UBA detects compromised accounts and insider threats by identifying behavioral anomalies against established baselines.","Managing accounts in Active Directory is an IAM directory services function; UBA analyzes behavioral patterns of existing users to detect insider threats or compromised accounts.","Automated patch deployment is a patch management function; UBA analyzes user behavioral patterns over time to detect anomalies indicating threats, not software vulnerabilities."]},
  {id:189,domain:O,question:"What is the purpose of a security awareness training program?",options:["Provide specialized hands-on configuration training for network engineers and IT staff responsible for managing perimeter firewall rule sets","Educate all employees about security threats, safe behaviors, and their security responsibilities","Offer CISSP, CEH, and Security+ exam preparation coursework exclusively to credentialed information security professionals seeking advanced certification","Run automated vulnerability scanning tools against production systems to discover unpatched software flaws and misconfigured service endpoints"],answer:1,explanation:"Security awareness training reduces human-related risks by teaching employees to recognize and avoid threats.",optionExplanations:["Specialized IT staff training is technical skills development; security awareness training targets all employees to recognize threats and practice safe behaviors in their daily work.","Security awareness training reduces risk from phishing, social engineering, and poor security habits across the workforce.","Certification exam preparation trains individual security professionals; security awareness training is organization-wide, targeting every employee regardless of their technical security background.","Automated vulnerability scanning discovers technical weaknesses in systems; security awareness training educates employees about social engineering, phishing, and safe behaviors to reduce human risk."]},
  {id:190,domain:O,question:"What is the purpose of a disaster recovery plan (DRP)?",options:["Implement proactive preventive controls aimed at eliminating the likelihood of all system outages before any disruption can possibly occur","Provide detailed technical procedures to recover IT systems after a catastrophic event","Identify, assess, and prioritize enterprise-wide operational risks and apply mitigation controls through a centralized risk governance framework","Conduct regular fire drills and emergency response training to teach staff evacuation procedures and safety protocols during physical emergencies"],answer:1,explanation:"A DRP specifies how to restore IT systems and infrastructure after disasters like fires, floods, or ransomware attacks.",optionExplanations:["Preventing all disasters is the goal of risk management controls, not a DRP; a DRP provides reactive recovery procedures for after a catastrophic event has already occurred.","A DRP provides step-by-step procedures for restoring specific IT systems and services after a major disruption.","Enterprise risk management addresses risk across the organization; a DRP specifically provides the technical recovery steps for restoring IT infrastructure after a disaster.","Emergency evacuation drills are physical safety exercises; a DRP focuses specifically on technical IT recovery procedures to restore systems after a technology-impacting disaster."]},
  {id:191,domain:O,question:"Which of the following BEST describes the principle of least privilege in IAM?",options:["Grant IT administrators unrestricted root-level access to every system, database, and application within the organization by default","Users are granted the minimum access rights needed for their job function","All users share the same access level","Expand employee system permissions progressively as they accumulate additional years of service and tenure within the organization"],answer:1,explanation:"Least privilege minimizes the attack surface by ensuring users cannot access more than their job requires.",optionExplanations:["Unrestricted administrator access violates least privilege; the principle requires granting only the minimum rights necessary for each job function, including for IT staff.","Least privilege ensures each user has only the permissions necessary for their specific job function.","Uniform access levels violate least privilege by giving everyone the same rights regardless of role.","Seniority-based access contradicts least privilege; permissions should be tied to job requirements and specific roles, not length of employment."]},
  {id:192,domain:O,question:"What is a security information and event management (SIEM) correlation rule?",options:["A firewall access control entry that drops packets matching known malicious source IP addresses, ports, or traffic signatures","Logic that combines multiple events to identify patterns indicating a security threat","An AES-based encryption algorithm applied to log entries before they are transmitted to or stored in long-term archival systems","A role-based access control policy document specifying which systems and data each user group can access based on their job title"],answer:1,explanation:"Correlation rules in a SIEM aggregate related events from multiple sources to detect threats that individual alerts would miss.",optionExplanations:["A firewall rule blocks traffic based on network attributes; a SIEM correlation rule analyzes collected log events from multiple sources to identify threat patterns, not block packets.","Correlation rules link events across systems — e.g., multiple failed logins followed by a success — to detect attacks.","Encrypting log data is a data protection measure; a SIEM correlation rule is analytical logic that combines event data to surface threat patterns requiring investigation.","An access control policy governs permissions; a SIEM correlation rule is detection logic that identifies suspicious patterns in aggregated security event data."]},
  {id:193,domain:O,question:"Which of the following is a key step in identity lifecycle management?",options:["Firewall rule creation","Provisioning and deprovisioning user accounts as roles change","Encrypting email communications","Scanning for vulnerabilities"],answer:1,explanation:"Identity lifecycle management covers creating, modifying, and removing access rights as employees join, move, and leave.",optionExplanations:["Firewall rules control network access; identity lifecycle is about user account management.","Provisioning (creating access) and deprovisioning (removing access) are core identity lifecycle activities.","Email encryption is a communication security control, not identity lifecycle management.","Vulnerability scanning is a security assessment activity, not identity management."]},
  {id:194,domain:O,question:"What is a rogue access point?",options:["An access point with a weak WPA2 password","An unauthorized wireless access point connected to the corporate network","An access point broadcasting on a non-standard channel","An access point used for guest Wi-Fi"],answer:1,explanation:"A rogue AP is an unauthorized access point connected to the corporate network, creating an uncontrolled entry point.",optionExplanations:["A weak password is a misconfiguration; a rogue AP is an unauthorized device.","A rogue access point bypasses corporate security controls by creating an unsanctioned wireless entry point.","Non-standard channel configurations are wireless settings; a rogue AP is about authorization.","Guest Wi-Fi is an authorized (often isolated) network; rogue APs are unauthorized."]},
  {id:195,domain:O,question:"Which of the following BEST describes a cold site disaster recovery facility?",options:["A fully operational secondary data center with synchronized hardware and live, continuous data replication providing immediate failover capability","A facility with infrastructure (power, cooling, racks) but no hardware or data — requires days to weeks to be operational","A containerized modular data center that ships to the disaster location and can be made operational within hours of physical arrival","A cloud-based subscription service that stores encrypted data backups offsite and restores them to cloud virtual machines on demand"],answer:1,explanation:"A cold site has the physical infrastructure but requires significant setup time (equipment, data restore) before use.",optionExplanations:["Immediate failover with live replication describes a hot site; a cold site has no hardware or data and takes days to weeks to become operational.","A cold site has physical space, power, and cooling but no pre-configured hardware; recovery takes days to weeks.","A rapidly deployable mobile facility describes a warm or portable site option; a cold site is a pre-existing facility that still requires hardware procurement and setup.","Cloud backup-and-restore describes an offsite cloud recovery service; a cold site is a physical facility with basic infrastructure but requiring hardware installation before use."]},
  {id:196,domain:O,question:"What is a hot site in disaster recovery?",options:["A secondary data center geographically located in a region that experiences a warmer year-round ambient temperature and climate","A fully equipped and operational recovery facility with mirrored data, ready for immediate failover","A facility requiring 1-3 days to become operational","A trailer-mounted portable server deployment unit that can be transported to a disaster-affected site to provide emergency computing capacity"],answer:1,explanation:"A hot site mirrors the production environment and can take over within minutes to hours of a disaster.",optionExplanations:["Geographic climate has no bearing on DR site classification; a hot site is defined by its immediate operational readiness with mirrored systems, not its physical location's temperature.","A hot site replicates production systems and data in real time, enabling near-instantaneous failover.","Requiring 1-3 days to become operational describes a warm site.","A mobile unit describes a portable or containerized recovery solution; a hot site is a fixed secondary facility with fully mirrored systems ready for immediate failover."]},
  {id:197,domain:O,question:"What is the purpose of change management in IT security?",options:["Maintain a continuously updated network topology diagram documenting every switch port, router interface, and firewall connection in the environment","Ensure changes to systems are reviewed, tested, and approved to prevent unintended security impacts","Configure all managed endpoints to automatically download and install operating system patches immediately upon vendor release without approval","Update human resources records and email distribution lists whenever employees transfer departments, change job titles, or leave the organization"],answer:1,explanation:"Change management prevents unauthorized or poorly tested changes from introducing vulnerabilities or outages.",optionExplanations:["Network topology documentation is configuration management; change management governs the review, approval, and testing process before any change is applied to production systems.","Change management requires review, testing, and approval before any system change, preventing security regressions.","Auto-applying patches without review bypasses change management controls; proper change management requires testing and approval to prevent patches from introducing new security issues.","HR record updates are personnel management activities; IT change management specifically controls and tracks changes to systems and infrastructure to prevent unintended security impacts."]},
  {id:198,domain:O,question:"Which of the following BEST describes security orchestration?",options:["Manually configuring security tools one at a time","Integrating and automating multiple security tools to work together efficiently","Training security staff on multiple tools","Centralizing all logs in a single system"],answer:1,explanation:"Orchestration connects disparate security tools via APIs to automate workflows spanning multiple systems.",optionExplanations:["Manual configuration is the opposite of orchestration.","Security orchestration integrates tools (firewall, SIEM, EDR, ticketing) via APIs to automate complex security workflows.","Staff training is an administrative control; orchestration is a technical automation capability.","Centralizing logs is log management or SIEM; orchestration coordinates actions across tools."]},
  {id:199,domain:O,question:"What is the function of an endpoint detection and response (EDR) tool?",options:["Block every executable file from running on an endpoint regardless of its digital signature reputation or vendor certificate status","Monitor endpoint behavior, detect advanced threats, and enable rapid investigation and response","Serve as a complete drop-in replacement for all legacy signature-based antivirus products installed on every managed endpoint device","Apply BitLocker or FileVault full-disk encryption to every managed laptop and desktop device enrolled in the endpoint management system"],answer:1,explanation:"EDR collects telemetry, detects behavioral anomalies, and provides investigation tools including process trees and IOC correlation.",optionExplanations:["Blocking all executables describes an extreme application control posture; EDR monitors behavior and investigates threats at runtime rather than statically preventing all execution.","EDR continuously monitors endpoints for suspicious behavior, provides detection, and supports forensic investigation.","EDR supplements or replaces AV but is defined by behavioral monitoring and investigation capabilities, not simply replacing antivirus signature scanning on endpoints.","Full-disk encryption protects data confidentiality on physical media; EDR detects and responds to active threats through behavioral monitoring of running processes and activities."]},
  {id:200,domain:O,question:"What is the purpose of network traffic analysis (NTA)?",options:["Apply mandatory TLS encryption to every communication flow between internal endpoints traversing the corporate network infrastructure","Analyze patterns of network traffic to detect threats, anomalies, and policy violations","Maintain a threat intelligence-driven blacklist of known-malicious IP addresses and reject all inbound connection attempts from those sources","Configure, update, and replicate DNS zone records across authoritative name servers for all internal and external organizational domains"],answer:1,explanation:"NTA (also called NDR) inspects traffic flows to detect C2 communication, lateral movement, and data exfiltration.",optionExplanations:["Encrypting network traffic is a confidentiality control; NTA inspects traffic metadata and behavioral patterns to detect anomalies and threats, not encrypt communications.","NTA examines network flow data and packet content to detect malicious activity, anomalies, and unauthorized transfers.","IP blocklisting is a specific access control measure; NTA broadly analyzes all traffic patterns and flows to surface anomalies, not just block specific known-bad addresses.","DNS zone management is a network administration task; NTA analyzes network traffic patterns and flows to detect threats, not manage name resolution infrastructure."]},
  {id:201,domain:O,question:"What does a penetration tester do during the 'reconnaissance' phase?",options:["Exploit identified vulnerabilities","Gather information about the target using both passive and active techniques","Report findings to the client","Cover tracks after exploitation"],answer:1,explanation:"Reconnaissance is the information-gathering phase — OSINT, DNS lookups, port scanning to map the attack surface.",optionExplanations:["Exploiting vulnerabilities is the exploitation phase, which comes after reconnaissance.","Reconnaissance collects target information through passive means (OSINT) and active means (port scanning).","Reporting findings is the final phase after testing is complete.","Covering tracks is a post-exploitation activity; reconnaissance comes first."]},
  {id:202,domain:O,question:"What is the purpose of a security audit?",options:["Run scheduled automated vulnerability scans on all production systems to catalog unpatched software weaknesses and configuration flaws","Systematically evaluate security controls, policies, and procedures against a standard or compliance requirement","Deliver annual phishing simulations and interactive security e-learning modules to measure and improve employee security awareness levels","Activate the incident response team to contain, eradicate, and recover from an ongoing security breach affecting organizational systems"],answer:1,explanation:"A security audit provides an independent evaluation of whether controls meet defined standards or compliance requirements.",optionExplanations:["Automated vulnerability scanning is a technical assessment activity; a security audit systematically evaluates controls and procedures against a compliance standard, not just scan for vulnerabilities.","A security audit assesses compliance with policies, frameworks, and regulatory requirements.","Security awareness training educates employees; a security audit evaluates whether controls, policies, and procedures meet defined standards, not train staff or measure their behavior.","Incident response handles active breaches; a security audit proactively evaluates controls against standards to identify gaps before incidents occur, not respond to them."]},
  {id:203,domain:O,question:"Which of the following BEST describes a false negative in security monitoring?",options:["An alert generated for a benign event","A confirmed security incident that was correctly detected","A real attack that was not detected by security controls","A vulnerability scan that finds no issues"],answer:2,explanation:"A false negative is a missed detection — a real threat that security tools failed to identify.",optionExplanations:["A benign event incorrectly flagged is a false positive.","A correctly detected real attack is a true positive.","A false negative means a real attack occurred but was not detected — it slipped through security controls.","No issues found in a scan could be accurate (true negative) or missed (false negative)."]},
  {id:204,domain:O,question:"What is the purpose of a certificate pinning?",options:["Use a hardware security module to generate, store, and protect cryptographic private keys from unauthorized extraction or export","Hardcode a specific certificate or public key into an application to prevent MITM attacks","Optimize TLS connection performance by caching session parameters and using abbreviated handshakes for returning clients and connections","Trigger OCSP or CRL updates automatically whenever a certificate authority detects that a private key has been compromised"],answer:1,explanation:"Certificate pinning rejects any certificate that doesn't match the pinned value, preventing attackers from substituting a fraudulent cert.",optionExplanations:["An HSM securely stores cryptographic keys; certificate pinning hardcodes a specific certificate or public key in an application to reject any other certificate during TLS connections.","Pinning binds an application to a specific certificate/key, preventing attackers from inserting a fraudulent CA-signed cert.","TLS session resumption speeds up repeated connections; certificate pinning associates a specific certificate with an application to prevent MITM attacks using fraudulent certificates.","OCSP and CRL handle certificate revocation status; certificate pinning ties an app to a specific certificate, preventing MITMs from substituting a different valid certificate."]},
  {id:205,domain:O,question:"What is the purpose of user account deprovisioning?",options:["Assign additional privileges when an employee is promoted","Remove access rights when an employee leaves or changes roles","Create new accounts for new employees","Reset passwords for locked accounts"],answer:1,explanation:"Deprovisioning removes all access rights when someone leaves or changes roles, preventing unauthorized access by former employees.",optionExplanations:["Assigning additional privileges is provisioning or access review, not deprovisioning.","Deprovisioning removes access rights promptly when an employee departs or changes roles, closing potential insider threat vectors.","Creating accounts is provisioning, not deprovisioning.","Password resets are account maintenance activities; deprovisioning removes the account or all its access."]},
  {id:206,domain:P,question:"What is risk management in information security?",options:["Applying maximum security controls across every system and process to completely eliminate all identified risk from the organization","Identifying, assessing, and prioritizing risks then applying controls to reduce them to an acceptable level","Shifting the entire financial burden of all potential security incidents to a third-party cyber insurance provider or outsourced contractor","Recording every detected security alert, incident, and near-miss event in a centralized ticketing system to maintain an audit trail"],answer:1,explanation:"Risk management is the ongoing process of identifying risks, evaluating their likelihood/impact, and deciding how to treat them.",optionExplanations:["Eliminating all risk is impossible and not the goal; risk management accepts that some residual risk remains and aims to reduce risk to a defined acceptable level.","Risk management evaluates threats, vulnerabilities, and impact to prioritize risk treatment options.","Risk transfer via insurance is one risk response option, not the complete definition of risk management, which also includes accepting, avoiding, and mitigating risks.","Documenting incidents is an operational security practice; risk management is the structured process of identifying, assessing, prioritizing, and treating risks before they become incidents."]},
  {id:207,domain:P,question:"Which of the following are the four main risk treatment options?",options:["Accept, Avoid, Transfer, Mitigate","Ignore, Report, Escalate, Document","Scan, Patch, Monitor, Report","Plan, Do, Check, Act"],answer:0,explanation:"Risk treatment options: Accept (tolerate), Avoid (eliminate), Transfer (insure/outsource), Mitigate (reduce likelihood/impact).",optionExplanations:["Accept, Avoid, Transfer, and Mitigate (or Reduce) are the four standard risk treatment strategies.","Ignore/Report/Escalate/Document describes process steps, not formal risk treatment options.","Scan/Patch/Monitor/Report describes vulnerability management activities, not risk treatment options.","Plan-Do-Check-Act is the PDCA management cycle from ISO standards."]},
  {id:208,domain:P,question:"What is a business impact analysis (BIA)?",options:["A detailed review of technology procurement costs and vendor contracts to optimize departmental IT budget allocation and spending","An assessment identifying critical business functions and quantifying the impact of disruption","An automated dynamic and static testing assessment that identifies unpatched security vulnerabilities in production web applications and services","An authorized simulated cyberattack on network infrastructure to identify and demonstrate exploitable vulnerabilities before real attackers discover them"],answer:1,explanation:"A BIA identifies critical processes, their dependencies, and quantifies downtime impact to prioritize recovery.",optionExplanations:["A financial IT audit examines costs and spending; a BIA identifies which business functions are critical and quantifies the operational impact if those functions are disrupted.","A BIA determines which business processes are critical, how long they can be down (RTO), and data loss tolerance (RPO).","Application vulnerability scanning finds security flaws in code; a BIA assesses business process criticality and the financial or operational impact of service disruptions.","A penetration test simulates attacks to find technical vulnerabilities; a BIA evaluates business function criticality and disruption impact to inform recovery planning priorities."]},
  {id:209,domain:P,question:"What is the purpose of a risk register?",options:["Log all security incidents","Document identified risks, their likelihood, impact, and treatment plans","Track software patches","Store audit reports"],answer:1,explanation:"A risk register is a living document cataloguing all identified risks with their ratings, owners, and treatment status.",optionExplanations:["Security incident logging is the function of SIEM and incident management systems.","A risk register records each identified risk with probability, impact rating, owner, and treatment plan.","Patch tracking is handled by vulnerability management and patch management systems.","Audit reports document compliance findings; a risk register tracks ongoing risk management."]},
  {id:210,domain:P,question:"What is data classification?",options:["Organizing files into folders","Categorizing data based on its sensitivity to apply appropriate security controls","Encrypting sensitive data","Scanning data for malware"],answer:1,explanation:"Data classification assigns sensitivity levels (e.g., Public, Internal, Confidential, Secret) to guide security controls.",optionExplanations:["File organization is a data management task; data classification applies security-relevant labels.","Data classification assigns sensitivity labels so appropriate access controls, encryption, and handling procedures can be applied.","Encryption is a control applied based on classification; classification itself is the labeling process.","Malware scanning is endpoint security; data classification determines sensitivity levels."]},
  {id:211,domain:P,question:"What does GDPR primarily regulate?",options:["Financial reporting requirements","The processing and protection of personal data of EU residents","Cybersecurity standards for critical infrastructure","Software export controls"],answer:1,explanation:"GDPR (General Data Protection Regulation) governs how organizations collect, process, and store EU residents' personal data.",optionExplanations:["Financial reporting is regulated by laws like Sarbanes-Oxley (SOX); GDPR covers personal data.","GDPR sets strict requirements for processing personal data of EU data subjects, regardless of where the processor is located.","Critical infrastructure cybersecurity is covered by sector-specific regulations like NIS2, not GDPR.","Software export controls are handled by export control laws like EAR/ITAR."]},
  {id:212,domain:P,question:"What is HIPAA primarily concerned with?",options:["Financial data security","Protection of protected health information (PHI) in the United States","Secure software development practices","Consumer credit reporting"],answer:1,explanation:"HIPAA (Health Insurance Portability and Accountability Act) protects the privacy and security of PHI.",optionExplanations:["Financial data is regulated by SOX, PCI DSS, and GLBA; HIPAA covers health information.","HIPAA mandates safeguards for protected health information (PHI) in healthcare organizations and their business associates.","Secure software development is guided by SDLC frameworks and OWASP; HIPAA is health data regulation.","Consumer credit reporting is regulated by FCRA; HIPAA covers health information only."]},
  {id:213,domain:P,question:"What is PCI DSS?",options:["A government regulation for banking","A security standard for organizations that handle credit card data","An encryption protocol for financial transactions","A data classification scheme for financial data"],answer:1,explanation:"PCI DSS (Payment Card Industry Data Security Standard) defines security requirements for cardholder data environments.",optionExplanations:["PCI DSS is a private industry standard created by major card brands, not a government regulation.","PCI DSS sets technical and operational requirements for organizations that store, process, or transmit payment card data.","PCI DSS is a security standard; TLS is the encryption protocol used for secure financial transactions.","PCI DSS contains data classification requirements within it; it is not itself a classification scheme."]},
  {id:214,domain:P,question:"What is the NIST Cybersecurity Framework (CSF)?",options:["A mandatory US government regulation","A voluntary framework with five functions: Identify, Protect, Detect, Respond, Recover","A certification for security professionals","A technical standard for encrypting government data"],answer:1,explanation:"The NIST CSF is a voluntary risk-based framework helping organizations manage cybersecurity risk through five core functions.",optionExplanations:["The NIST CSF is voluntary for most organizations; only some federal requirements make it mandatory.","The NIST CSF organizes cybersecurity activities into five functions: Identify, Protect, Detect, Respond, Recover.","NIST CSF is an organizational framework; Security+ and CISSP are security certifications.","NIST FIPS standards (like FIPS 140) govern encryption for government; CSF is a broader risk management framework."]},
  {id:215,domain:P,question:"What is ISO 27001?",options:["A protocol for encrypting data in transit","An international standard for establishing an Information Security Management System (ISMS)","A US government security clearance","A firewall configuration standard"],answer:1,explanation:"ISO 27001 provides a framework for establishing, implementing, maintaining, and continuously improving an ISMS.",optionExplanations:["Data encryption protocols are technical standards like TLS; ISO 27001 is a management system standard.","ISO 27001 is the globally recognized standard for implementing a structured ISMS to manage information security risks.","Security clearances are government personnel designations; ISO 27001 is an organizational management system standard.","Firewall configuration is a technical control; ISO 27001 defines the overall management system requirements."]},
  {id:216,domain:P,question:"What is the purpose of a security policy?",options:["Provide technical instructions for configuring systems","Define organizational expectations, rules, and responsibilities for information security","Test systems for vulnerabilities","Encrypt sensitive data"],answer:1,explanation:"Security policies establish management's intent and requirements; technical standards and procedures implement them.",optionExplanations:["Technical configuration instructions are documented in technical standards and procedures, not high-level policies.","A security policy defines high-level rules, responsibilities, and consequences for security-related behavior.","Vulnerability testing is a technical activity guided by policy; the policy itself does not perform testing.","Encryption is a technical control; the policy mandates its use without specifying implementation details."]},
  {id:217,domain:P,question:"Which of the following BEST describes third-party risk management?",options:["Managing risks from software bugs","Assessing and managing security risks introduced by vendors, suppliers, and partners","Tracking patch compliance for third-party software","Encrypting data shared with third parties"],answer:1,explanation:"Third-party risk management evaluates vendor security practices and contractual obligations to manage supply chain risk.",optionExplanations:["Software bug risks are managed through patch management and software assurance.","Third-party risk management assesses vendor security posture, contractual controls, and ongoing compliance monitoring.","Patch compliance for vendor software is a component of vulnerability management, not the full scope of third-party risk.","Data encryption when sharing with third parties is a data protection control within a broader third-party risk program."]},
  {id:218,domain:P,question:"What is the purpose of a privacy impact assessment (PIA)?",options:["Conduct dynamic application security testing and static code analysis on a system to identify exploitable security vulnerabilities","Evaluate how a project or system collects, uses, and protects personal information","Label all data assets with a sensitivity classification tier based on regulatory requirements and potential business impact if disclosed","Review financial transaction logs and access records systematically to detect unauthorized modifications or fraudulent activity entries"],answer:1,explanation:"A PIA (or DPIA under GDPR) identifies privacy risks in new systems or processes involving personal data.",optionExplanations:["Security testing finds technical vulnerabilities in systems; a PIA specifically evaluates how a project handles personal information and its impact on individuals' privacy rights.","A PIA assesses the privacy implications of collecting and processing personal data, identifying risks and required controls.","Data classification assigns sensitivity labels to data; a PIA evaluates the collection, use, and protection of personal information within a specific project or system.","Financial fraud auditing examines transaction records; a PIA specifically assesses how personal information is collected, used, and protected within a project or system."]},
  {id:219,domain:P,question:"What is the difference between a threat and a vulnerability?",options:["Threats and vulnerabilities are equivalent and interchangeable security terms that both describe exploitable weaknesses present in systems","A threat is a potential harm; a vulnerability is a weakness that can be exploited by a threat","A vulnerability is a potential harm; a threat is the weakness","Threats only affect external systems; vulnerabilities only affect internal systems"],answer:1,explanation:"Threat = actor or event that could cause harm. Vulnerability = weakness that could be exploited. Risk = threat × vulnerability × impact.",optionExplanations:["They are not equivalent; a threat is an actor or event that could cause harm, while a vulnerability is a specific weakness that a threat could exploit.","A threat is a potential harm or malicious actor; a vulnerability is the weakness the threat exploits to cause harm.","A vulnerability is the weakness, not the harm; the threat is what causes or could cause harm.","Both threats and vulnerabilities apply to both internal and external systems."]},
  {id:220,domain:P,question:"What is the purpose of due diligence in vendor selection?",options:["Request price reductions and favorable payment terms from vendors by comparing quotes against competing bids during procurement negotiations","Investigate a vendor's security practices, financial health, and compliance before entering a business relationship","Deliver security awareness training sessions to third-party contractor personnel who access company systems or facilities during engagements","Perform scheduled penetration testing against third-party vendor infrastructure to identify security weaknesses in their managed environments"],answer:1,explanation:"Due diligence verifies that a vendor's security posture, compliance, and practices meet organizational requirements before signing.",optionExplanations:["Contract negotiation seeks favorable pricing; due diligence investigates a vendor's security posture, financial stability, and compliance history before entering the business relationship.","Due diligence investigates a prospective vendor's security controls, certifications, and compliance to inform risk decisions.","Training vendor employees addresses a security concern but is not due diligence; due diligence investigates the vendor's existing security practices and compliance before contracting.","Pen testing vendor systems is an ongoing assurance activity; due diligence is the pre-contract investigation of a vendor's security posture before establishing the relationship."]},
  {id:221,domain:P,question:"What is a security controls assessment?",options:["Testing software code for bugs","Evaluating whether security controls are implemented correctly and operating effectively","Updating antivirus signatures","Training employees on security policies"],answer:1,explanation:"A controls assessment determines whether security controls are properly implemented and achieving their intended objectives.",optionExplanations:["Code testing is software quality assurance; controls assessment evaluates security mechanisms.","A security controls assessment verifies that controls are implemented, functional, and effective against intended threats.","Updating antivirus signatures is routine security maintenance, not a controls assessment.","Employee training is a people-focused control; assessing whether training is effective would be part of the assessment."]},
  {id:222,domain:P,question:"What is the purpose of a security metrics program?",options:["Generate automated scripts that configure firewall rules and IDS signatures dynamically based on incoming threat intelligence feeds","Measure the effectiveness of security controls and demonstrate security posture to management","Use configuration management platforms to deploy, configure, and update security agents and tooling across all enterprise endpoints","Record which employees have completed mandatory compliance training modules and report completion percentages to the HR management system"],answer:1,explanation:"Security metrics provide quantitative measures (time to patch, MTTD, MTTR, percentage encrypted) to assess and communicate security effectiveness.",optionExplanations:["Automated security configuration is a technical hardening task; a security metrics program measures the effectiveness of controls and communicates security posture data to stakeholders.","Security metrics quantify control effectiveness, enabling data-driven decisions and management communication.","Deploying security tools is an operational task; a security metrics program measures how effectively security controls perform and reports those results to management stakeholders.","Tracking training completion is a subset activity; a security metrics program comprehensively measures security control effectiveness across all domains, not just training compliance."]},
  {id:223,domain:P,question:"What is an acceptable use policy (AUP)?",options:["A contract with cloud providers","A policy defining how employees may use organizational technology resources","A document specifying encryption requirements","A policy for managing third-party vendor access"],answer:1,explanation:"An AUP defines permitted and prohibited uses of company systems, networks, and data by employees.",optionExplanations:["Cloud provider contracts are service agreements; AUPs are internal employee policies.","An AUP sets expectations for appropriate use of IT resources including computers, internet, and email.","Encryption requirements are defined in technical security standards and data protection policies.","Vendor access policies govern third-party access; AUPs govern employee use of company resources."]},
  {id:224,domain:P,question:"What is a SOC 2 report?",options:["A federally mandated cybersecurity certification that organizations must obtain before being authorized to operate critical government information systems","A third-party audit report on a service organization's security, availability, and privacy controls","A technical benchmark specifying required firewall configurations, router hardening settings, and network architecture design standards","A findings document produced by an ethical hacking team describing vulnerabilities and exploits discovered during an authorized offensive test"],answer:1,explanation:"SOC 2 (System and Organization Controls 2) is a third-party audit assessing a service provider's controls for Trust Service Criteria.",optionExplanations:["Government-mandated IT authorizations include FedRAMP or FISMA, not SOC 2; a SOC 2 report is a voluntary third-party audit of a service organization's security controls.","SOC 2 reports are issued by independent auditors evaluating service organizations' controls for security, availability, confidentiality, and privacy.","Network configuration benchmarks are found in standards like CIS Benchmarks; a SOC 2 report audits an organization's security, availability, and privacy controls against Trust Service Criteria.","A penetration test report details discovered vulnerabilities; a SOC 2 report is a formal third-party audit of a service provider's control environment for security and availability."]},
  {id:225,domain:P,question:"Which regulation focuses on protecting consumer financial data in the United States?",options:["GDPR","HIPAA","GLBA","PCI DSS"],answer:2,explanation:"GLBA (Gramm-Leach-Bliley Act) requires financial institutions to protect consumer financial information.",optionExplanations:["GDPR is an EU privacy regulation covering all personal data, not specifically US financial data.","HIPAA protects health information; GLBA protects consumer financial data.","GLBA (Gramm-Leach-Bliley Act) mandates that financial institutions protect the privacy and security of consumer financial information.","PCI DSS is a payment card industry standard, not a consumer financial data protection regulation."]},
  {id:226,domain:G,question:"What is the purpose of a key management lifecycle?",options:["Generate passwords for user accounts","Govern creation, distribution, storage, rotation, and destruction of cryptographic keys","Manage TLS certificate expiration dates","Authenticate users to directory services"],answer:1,explanation:"Key lifecycle management ensures keys are generated securely, distributed safely, rotated regularly, and destroyed when no longer needed.",optionExplanations:["Password management is handled by IAM systems; key management covers cryptographic keys.","The key management lifecycle covers all stages: generation, distribution, storage, rotation, revocation, and destruction.","Certificate lifecycle management is related but distinct from the cryptographic key management lifecycle.","Directory service authentication uses LDAP/Kerberos; key management governs the cryptographic keys themselves."]},
  {id:227,domain:G,question:"What is the difference between authentication and authorization?",options:["They are the same process","Authentication verifies identity; authorization determines what an authenticated user can access","Authorization verifies identity; authentication grants access","Authentication only applies to humans; authorization to systems"],answer:1,explanation:"Authentication proves who you are; authorization determines what you're allowed to do once identified.",optionExplanations:["They are sequential but distinct: authentication comes first, then authorization.","Authentication proves identity (who are you?); authorization determines permissions (what can you do?).","Authorization follows authentication; it never comes before identity verification.","Both authentication and authorization apply to users, services, APIs, and machine identities."]},
  {id:228,domain:T,question:"Which of the following is the MOST effective defense against ransomware?",options:["Strong passwords","Offline, air-gapped backups tested regularly","Antivirus software alone","Blocking all email attachments"],answer:1,explanation:"Immutable, air-gapped backups ensure data can be restored even if ransomware encrypts all connected storage.",optionExplanations:["Strong passwords help prevent unauthorized access but do not recover encrypted data.","Air-gapped backups that cannot be reached by ransomware and are regularly tested are the best recovery option.","Antivirus alone cannot stop all ransomware, especially zero-day or fileless variants; backups are the safety net.","Blocking all attachments is overly restrictive and does not address all ransomware delivery methods (web, USB, RDP)."]},
  {id:229,domain:O,question:"What is the purpose of a tabletop exercise in incident response planning?",options:["Execute a live production failover to the disaster recovery site and validate that all systems and data restore correctly","Walk through a simulated scenario to identify gaps in plans without activating real systems","Run automated vulnerability scanners against live production servers to identify unpatched software weaknesses before attackers can exploit them","Deliver hands-on technical training sessions teaching security staff to operate and configure newly deployed security software and tools"],answer:1,explanation:"Tabletop exercises build team familiarity with IR processes and reveal plan gaps in a low-risk discussion format.",optionExplanations:["A live failover test activates real systems; a tabletop exercise is purely discussion-based and identifies planning gaps without triggering any real system changes or failovers.","Tabletop exercises use hypothetical scenarios to exercise decision-making and communication without disrupting production.","Vulnerability scanning assesses technical security posture; a tabletop exercise verbally walks through incident scenarios to identify gaps in response plans, not scan for vulnerabilities.","Technical training builds operational skills; a tabletop exercise tests the decision-making and coordination processes within existing incident response plans through scenario discussion."]},
  {id:230,domain:P,question:"What is a data retention policy?",options:["A technical standard specifying which encryption algorithms and minimum key lengths must be applied to protect data stored at rest","A policy defining how long data must be kept and when it must be securely deleted","A timetable specifying when full, incremental, and differential backups are performed and how long backup copies are retained","A framework that categorizes organizational data assets by sensitivity level and assigns handling and protection requirements to each tier"],answer:1,explanation:"Data retention policies define minimum and maximum periods for keeping data, balancing legal requirements with storage costs and privacy.",optionExplanations:["An encryption standard defines how data is secured; a data retention policy addresses how long data is kept and when it must be securely deleted, not how it is encrypted.","A data retention policy specifies required retention periods and disposal methods for different data categories.","A backup schedule governs when copies are made; a data retention policy defines how long original operational data and records must be kept before mandatory secure deletion.","A data classification framework labels data by sensitivity; a retention policy defines how long data must be kept and when it must be permanently and securely deleted."]},
  {id:231,domain:G,question:"Which of the following BEST describes a pseudo-random number generator (PRNG) used in cryptography?",options:["Generates numbers that are truly unpredictable","Generates sequences that appear random but are deterministic from a seed","Uses quantum mechanics for randomness","Requires user input to generate each number"],answer:1,explanation:"PRNGs use a seed to generate deterministic but statistically random-appearing sequences; CSPRNGs add unpredictability for crypto use.",optionExplanations:["Truly unpredictable randomness is provided by a TRNG (True Random Number Generator) using physical entropy sources.","PRNGs generate deterministic sequences from a seed value; Cryptographically Secure PRNGs (CSPRNGs) use additional entropy.","Quantum RNGs are TRNGs using quantum phenomena; CSPRNGs are algorithmic.","PRNGs are algorithmic and do not require user input for each value."]},
  {id:232,domain:G,question:"What is the purpose of a message authentication code (MAC)?",options:["Provide confidentiality","Verify message integrity and authenticity using a shared secret key","Create a digital signature using asymmetric keys","Manage network MAC addresses"],answer:1,explanation:"A MAC (e.g., HMAC) uses a shared secret key to create a tag verifying both message integrity and sender authenticity.",optionExplanations:["MACs provide integrity and authenticity, not confidentiality; encryption provides confidentiality.","A MAC is computed with a shared secret key to detect tampering and verify the sender has the shared key.","Digital signatures use asymmetric keys (private key signs); MACs use symmetric shared keys.","Network MAC (Media Access Control) addresses are Layer 2 identifiers, completely unrelated to message authentication codes."]},
  {id:233,domain:G,question:"What type of encryption does TLS use for the bulk of data transfer after the handshake?",options:["Asymmetric encryption exclusively","Symmetric encryption (e.g., AES) for speed","Hashing for data protection","No encryption — only integrity checking"],answer:1,explanation:"TLS uses asymmetric crypto only during the handshake to establish keys; symmetric AES encrypts the actual data.",optionExplanations:["Asymmetric encryption is used only during the TLS handshake for key exchange and authentication.","After the TLS handshake establishes shared session keys, symmetric encryption (AES) encrypts bulk data for speed.","Hashing provides integrity (via HMAC in TLS); it does not encrypt data.","TLS provides both encryption and integrity; it does not rely solely on integrity checking."]},
  {id:234,domain:G,question:"What is an ephemeral key?",options:["A key stored permanently in an HSM","A temporary key generated for a single session and discarded afterward","A backup key used only in emergencies","A key shared between multiple users"],answer:1,explanation:"Ephemeral keys are generated fresh for each session, enabling perfect forward secrecy by not persisting after session end.",optionExplanations:["Permanent keys stored in HSMs are long-term keys; ephemeral keys are the opposite.","Ephemeral keys exist only for the duration of one session, ensuring past sessions cannot be decrypted if the long-term key is compromised.","Emergency backup keys are long-lived recovery keys, not ephemeral.","Shared keys are symmetric keys or key material; ephemeral keys are specific to a single session."]},
  {id:235,domain:G,question:"Which of the following BEST describes the concept of 'security through obscurity'?",options:["A robust security strategy based on hiding system architecture","Relying solely on secrecy of design rather than sound security controls — generally considered insufficient alone","An accepted industry-standard primary security control that uses design secrecy as the foundational and most effective protective layer","Protecting all technical documentation, architecture diagrams, and system runbooks with symmetric encryption to prevent unauthorized disclosure"],answer:1,explanation:"Security through obscurity hides implementation details but is not considered sufficient without actual security controls.",optionExplanations:["Hiding architecture might delay attackers but provides no real protection once discovered.","Security through obscurity relies on secrecy of design rather than the strength of controls; it should supplement, not replace, real security.","Security through obscurity is widely considered insufficient as a primary control; sound security must rely on robust controls that remain effective even if design details are known.","Encrypting documentation is a document security practice; security through obscurity refers to relying on keeping design details secret rather than implementing sound security controls."]},
  {id:236,domain:T,question:"What is a drive-by download attack?",options:["Physically removing a storage device from an unattended workstation to extract sensitive data through direct hardware media access","Malware installed on a system when a user visits a compromised website, without any user interaction","Clicking a malicious link or opening a weaponized attachment in a deceptive phishing email that installs malware on the victim","Copying sensitive files from an unlocked and unattended workstation left accessible in a shared office or public workspace"],answer:1,explanation:"Drive-by downloads exploit browser vulnerabilities to silently install malware when the user visits a compromised page.",optionExplanations:["Physical media theft is a physical security incident; a drive-by download installs malware through a browser when visiting a compromised website, requiring no physical access.","Drive-by downloads exploit browser or plugin vulnerabilities to install malware automatically upon visiting a malicious or compromised site.","Phishing-delivered malware requires user interaction with an email; drive-by downloads occur when visiting a compromised webpage, with malware installing silently without any user action.","Copying files from an unlocked computer is unauthorized physical access; drive-by downloads occur remotely through browser exploitation when a user visits a compromised website."]},
  {id:237,domain:T,question:"What is an XML injection attack?",options:["Embedding malicious JavaScript payloads within HTML web pages to execute client-side code in other authenticated users' browsers","Inserting malicious XML code into application input to manipulate XML parsers or backend systems","Flooding a web service endpoint with millions of malformed XML-formatted requests to exhaust server-side parsing and processing resources","Directly modifying XML-formatted application configuration files stored on a server to alter security settings and access control rules"],answer:1,explanation:"XML injection exploits applications that process XML input without proper validation, potentially altering data or structure.",optionExplanations:["Embedding JavaScript in web pages describes cross-site scripting (XSS); XML injection targets XML parsers and backend systems by inserting malicious XML into application inputs.","XML injection embeds malicious XML content to alter document structure, bypass security checks, or extract data.","Resource exhaustion through request flooding describes a denial-of-service attack; XML injection manipulates XML parser behavior to alter application logic, not overwhelm resources.","Directly editing server files requires file system access, not an injection attack; XML injection exploits unvalidated user input fields to insert malicious XML into parser processing."]},
  {id:238,domain:T,question:"What is a smurf attack?",options:["A type of social engineering using fake IT personas","A DDoS amplification attack using ICMP broadcast traffic","Malware that hides inside security software","A USB-based data exfiltration technique"],answer:1,explanation:"A smurf attack spoofs the victim's IP as the source in ICMP echo requests sent to a broadcast address, flooding the victim with replies.",optionExplanations:["Fake IT personas describe pretexting or IT impersonation social engineering.","A smurf attack exploits ICMP broadcasts: the attacker spoofs the victim's IP, causing an entire network to send replies to the victim.","Malware hiding in security software describes a Trojan or rootkit.","USB-based exfiltration is a physical data theft technique."]},
  {id:239,domain:T,question:"What is the purpose of a network sniffer in a security context?",options:["Block malicious traffic","Capture and analyze network packets for troubleshooting or malicious monitoring","Encrypt all network traffic","Scan systems for open ports"],answer:1,explanation:"Sniffers (Wireshark, tcpdump) capture raw packets; used legitimately for troubleshooting, maliciously for credential theft.",optionExplanations:["Blocking traffic is the function of firewalls and IPS, not sniffers.","A packet sniffer captures network traffic for analysis; in attacker hands it captures credentials, cookies, and data.","Encrypting traffic is done by protocols like TLS; sniffers analyze existing traffic.","Port scanning is active reconnaissance; sniffing is passive packet capture."]},
  {id:240,domain:T,question:"Which of the following BEST describes an on-path attack (formerly MITM)?",options:["An attack from an insider with elevated privileges","An attacker positioned between two communicating parties to intercept or modify traffic","A DDoS attack using multiple compromised systems","A targeted social engineering email campaign that sends fraudulent messages to executives to steal credentials or authorize fraudulent wire transfers"],answer:1,explanation:"An on-path attacker inserts themselves between client and server to eavesdrop or modify the communication.",optionExplanations:["An insider with elevated privileges describes a privileged insider threat, not an on-path attack.","An on-path (formerly MITM) attack positions the attacker to intercept, inspect, or alter communications between two parties.","DDoS uses many systems to flood a target; on-path attacks intercept targeted communication.","Targeting executives with fraudulent emails describes a whaling or spear-phishing attack; an on-path attack intercepts and potentially modifies traffic between two communicating parties."]},
  {id:241,domain:A,question:"What is a software-defined network (SDN)?",options:["A network infrastructure built using commodity white-box switching hardware running community open-source network operating systems","An architecture separating network control plane from data plane, enabling centralized programmatic control","A Wi-Fi network architecture that enforces WPA3 encryption using a centralized software-based key distribution and management system","A host-based packet filtering solution implemented entirely within the operating system kernel without requiring dedicated hardware"],answer:1,explanation:"SDN decouples the control plane (network intelligence) from the data plane (packet forwarding), enabling centralized management.",optionExplanations:["White-box networking uses open hardware but does not separate the control and data planes; SDN specifically decouples the control plane from the data plane for centralized management.","SDN separates control and data planes so network behavior can be programmatically controlled through a central controller.","WPA3 wireless encryption is a security protocol for Wi-Fi; SDN separates the network control plane from the data plane to enable centralized programmable network management.","A software firewall filters packets on a single host; SDN is a network architecture that centralizes control of the entire network fabric in a programmable controller."]},
  {id:242,domain:A,question:"What is the purpose of a content delivery network (CDN) from a security perspective?",options:["Apply TLS encryption to all web server responses to protect content confidentiality as data travels between the server and browser","Distribute traffic across many servers to improve availability and absorb DDoS attacks","Route remote employee traffic through an encrypted VPN tunnel to securely access internal corporate web applications and resources","Inspect all inbound HTTP and HTTPS requests using a web application firewall to detect and block malicious payloads and injections"],answer:1,explanation:"CDNs distribute content globally and can absorb volumetric DDoS attacks by distributing the load across many PoPs.",optionExplanations:["TLS encryption protects data in transit; a CDN distributes content across globally positioned edge nodes to absorb traffic load and provide DDoS mitigation at scale.","CDNs improve performance and availability by distributing traffic, and many CDN providers include DDoS mitigation services.","VPN provides secure remote access for employees; a CDN distributes content geographically to end users to improve availability and absorb volumetric DDoS attack traffic.","A WAF inspects application-layer requests for attack patterns; a CDN primarily provides geographic distribution and DDoS absorption, though some CDNs include WAF capabilities."]},
  {id:243,domain:A,question:"What is the function of a bastion host?",options:["Maintain an offsite encrypted data repository for long-term backup retention and rapid restoration following a catastrophic data loss event","A hardened gateway host providing secured access to an internal network from an untrusted network","A multi-tenant application server hosting multiple production web services behind a shared load balancer and reverse proxy configuration","A dedicated logging server that collects, centralizes, and stores all syslog, firewall, and flow event records for security monitoring"],answer:1,explanation:"A bastion host is a highly secured, minimized system exposed to the internet as the only entry point to a secure internal network.",optionExplanations:["An offsite backup repository stores data copies for recovery; a bastion host is a hardened network gateway providing controlled administrative access into a protected internal zone.","A bastion host is extensively hardened and serves as the single, audited entry point from public networks to secure zones.","A shared web application server hosts services for users; a bastion host is a hardened administrative gateway used by authorized personnel to access internal network resources securely.","A centralized log server collects security event data; a bastion host is a hardened access gateway for administrative connections into a protected network, not a logging system."]},
  {id:244,domain:A,question:"Which of the following BEST describes a jump server (jump box)?",options:["A dedicated server environment used only for software development, testing, and quality assurance activities, isolated from production systems","An intermediary server administrators must connect through to access other servers in a secure zone","A standby server configured to automatically assume primary service responsibilities when the main production server fails or becomes unavailable","A dedicated host that continuously scans all network-connected systems for unpatched software vulnerabilities and configuration weaknesses"],answer:1,explanation:"A jump server acts as an intermediary that admins must authenticate to before connecting to critical servers, creating a chokepoint for auditing.",optionExplanations:["A dev/test server is used for software development; a jump server is an intermediary administrative host that staff must authenticate through before accessing systems in secure zones.","A jump server is a hardened intermediary that forces all administrative access through a single, monitored hop.","An automatic failover server handles high availability; a jump server is a security control requiring administrators to route all management sessions through a single audited gateway.","A vulnerability scanning host probes systems for weaknesses; a jump server is an administrative access gateway that logs and controls all sessions to systems in secure network zones."]},
  {id:245,domain:A,question:"What is TLS inspection (SSL inspection)?",options:["Configure a network security appliance to reject and drop all TLS-encrypted sessions that cannot be decrypted and inspected inline","Decrypting TLS traffic at a proxy for security analysis, then re-encrypting it","Replacing TLS with a proprietary encryption protocol","Verifying that websites use valid TLS certificates"],answer:1,explanation:"TLS inspection decrypts encrypted traffic at a proxy/NGFW to inspect for malware or policy violations, then re-encrypts it.",optionExplanations:["Blocking uninspectable encrypted traffic is a policy choice; TLS inspection decrypts and re-encrypts traffic at a proxy to allow security analysis of the content within.","TLS inspection performs a man-in-the-middle decryption for security analysis, then re-encrypts with a trusted internal CA certificate.","TLS inspection uses standard TLS; it does not replace it with a proprietary protocol.","Certificate validation is performed by browsers; TLS inspection goes further by decrypting and inspecting the content."]},
  {id:246,domain:O,question:"What is security orchestration, automation and response (SOAR)?",options:["A purely human-driven incident handling process requiring security analysts to manually execute every containment and remediation step","Platforms that automate and orchestrate security workflows, reducing response times and human workload","A federal regulatory framework mandating that organizations notify government authorities within 72 hours of confirming a data breach","A signature-based network security appliance that passively monitors traffic flows and generates analyst alerts for recognized attack patterns"],answer:1,explanation:"SOAR integrates security tools, automates alert triage and playbook execution, and orchestrates responses across multiple systems.",optionExplanations:["Manual incident handling is traditional SecOps; SOAR automates and orchestrates those manual steps, integrating tools and workflows to reduce response times and analyst workload.","SOAR platforms automate routine tasks, orchestrate multi-tool workflows, and accelerate incident response.","Breach notification timelines are defined by regulations like GDPR and various state laws; SOAR is a technology platform that automates security workflow orchestration and response.","Passive signature-based detection describes an IDS; SOAR platforms actively automate and orchestrate response workflows across multiple security tools to reduce mean time to respond."]},
  {id:247,domain:O,question:"What is the purpose of a system hardening guide?",options:["Document network topology","Provide step-by-step configuration instructions to minimize system attack surface","Automate software deployment","Train users on secure password practices"],answer:1,explanation:"Hardening guides (like CIS Benchmarks) document specific configurations to disable unnecessary services and close attack vectors.",optionExplanations:["Network topology documentation is a network architecture task, not hardening.","Hardening guides specify configurations — disable unused ports/services, enable logging, apply patches — to reduce attack surface.","Automated deployment uses tools like Ansible; hardening guides define what to configure.","Password practice training is security awareness; hardening guides address technical system configurations."]},
  {id:248,domain:O,question:"What is a port scan and when is it used?",options:["Probing Fibre Channel and iSCSI storage area network ports to enumerate accessible storage volumes, LUNs, and shared data repositories","Using tools like Nmap to discover open ports and services on a target system","Configure firewall access control lists to deny traffic on all ports not explicitly required or approved by the organization","Capture and inspect packet payloads on designated TCP or UDP ports using a network protocol analyzer to examine application behavior"],answer:1,explanation:"Port scanning identifies open TCP/UDP ports and the services listening, revealing the attack surface of a system.",optionExplanations:["Enumerating storage network targets is SAN discovery; a port scan probes TCP/UDP ports on IP-connected hosts to discover what network services are running and accessible.","Port scanning (using Nmap, Masscan) identifies open ports and service versions for security assessment or attack reconnaissance.","Blocking unauthorized ports is a firewall hardening practice; a port scan is an active reconnaissance technique that enumerates open ports and listening services on target systems.","Protocol analysis inspects traffic on specific ports; a port scan actively probes many ports on targets to discover which are open and what services are listening."]},
  {id:249,domain:O,question:"What is a security information system (SIS) in industrial control?",options:["A security information and event management platform specifically tuned and deployed within industrial manufacturing and operational technology environments","A safety-critical system that shuts down industrial processes to prevent physical harm","A firewall between IT and OT networks","A network monitoring tool for SCADA systems"],answer:1,explanation:"Safety instrumented systems (SIS) are independent protective systems that automatically shut down processes when unsafe conditions are detected.",optionExplanations:["A SIEM aggregates and correlates security event logs; a safety instrumented system in industrial control specifically triggers automatic shutdowns to prevent physical harm to people.","A SIS monitors process conditions and executes safety functions (shutdowns) to prevent catastrophic failures.","Firewalls between IT and OT are network segmentation controls, not safety systems.","SCADA monitoring tools track operational data; SIS independently triggers safety shutdowns."]},
  {id:250,domain:O,question:"Which of the following BEST describes a security configuration management (SCM) process?",options:["Provisioning, rotating, and auditing user account passwords, API keys, and secrets across all enterprise systems and service accounts","Ensuring systems are configured consistently to security baselines and that changes are controlled","Planning and automating the scheduling of operating system and application patch deployments across all managed enterprise endpoints","Recording all physical and logical network device interconnections in a centralized network topology management and documentation database"],answer:1,explanation:"SCM tracks configurations, detects drift from baselines, and ensures changes go through proper approval processes.",optionExplanations:["Credential management handles user authentication secrets; security configuration management ensures systems adhere to security baselines and that configuration changes are reviewed and controlled.","SCM ensures systems maintain approved configurations, detects unauthorized changes, and manages configuration change approval.","Scheduling patch deployment is a patch management function; SCM ensures all systems consistently meet defined security configuration baselines and that deviations are detected and corrected.","Network topology documentation is a configuration management database (CMDB) function; SCM ensures systems are configured to security baselines and that changes are approved and tracked."]},
  {id:251,domain:P,question:"What is the purpose of a risk assessment?",options:["Train employees on security risks","Identify, analyze, and evaluate risks to determine appropriate risk treatment","Automate security monitoring","Document all security incidents"],answer:1,explanation:"A risk assessment evaluates threats, vulnerabilities, and potential impacts to prioritize risk treatment decisions.",optionExplanations:["Employee training is a risk treatment control that may result from an assessment, not the assessment itself.","Risk assessments systematically identify risks, analyze their likelihood and impact, and evaluate them against risk tolerance.","Automated monitoring is a detection control; risk assessment is a planning and evaluation process.","Incident documentation supports post-incident learning; risk assessment is a proactive planning activity."]},
  {id:252,domain:P,question:"What is the concept of 'due care' in information security?",options:["Maintaining a comprehensive risk register that documents every identified threat, its likelihood rating, and the potential business impact","Taking reasonable steps to protect an organization's assets and comply with legal obligations","Purchasing cyber liability insurance policies to contractually transfer the entire financial burden of all security incidents to the insurer","Contracting with external red team firms to perform authorized offensive security assessments against all production systems on an annual basis"],answer:1,explanation:"Due care means taking prudent, reasonable security actions — what a reasonable organization would do to protect its assets.",optionExplanations:["A risk register documents identified risks; due care is about taking reasonable protective steps and complying with legal obligations, not just documenting what risks exist.","Due care is the standard of reasonableness — implementing controls a responsible organization would use to protect assets.","Risk transfer via insurance is one risk response strategy; due care requires actively taking reasonable protective steps, not simply passing financial liability to an insurer.","Annual penetration testing is one security assurance practice; due care is a broader legal and ethical standard requiring ongoing reasonable protective measures across all security domains."]},
];
